{
  "name": "Wisdom-Guided Mindfulness Morning Phase",
  "description": "A high-performance mindfulness tracker focusing on the 5:00 AM to 12:00 PM phase, integrating traditional wisdom with AI-powered insights.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MorningTask {
  id: string;
  timeRange: string;
  titleEn: string;
  titleMy: string;
  descriptionEn: string;
  descriptionMy: string;
  isCompleted: boolean;
}

export interface MorningState {
  date: string;
  tasks: MorningTask[];
  wisdomQuote?: string;
  note?: string;
}

import { GoogleGenAI } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateDailyWisdom = async (tasksCompleted: number): Promise<string> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a short, powerful mindfulness wisdom quote for the morning. 
      The user has completed ${tasksCompleted} morning tasks. 
      Keep it poetic, grounding, and related to beginning a day with wisdom. 
      Include a one-sentence translation in Myanmar language.`,
      config: {
        temperature: 0.7,
        topP: 0.9,
      }
    });
    return response.text || "The breath is the bridge between body and mind. / ထွက်လေဝင်လေသည် ရုပ်နှင့်နာမ်ကို ဆက်သွယ်ပေးသော တံတားဖြစ်သည်။";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Silence is the root of wisdom. / ဆိတ်ငြိမ်ခြင်းသည် ပညာ၏ အခြေခံဖြစ်သည်။";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { MorningState, MorningTask } from './types';
import { generateDailyWisdom } from './services/gemini';

const INITIAL_TASKS: MorningTask[] = [
  {
    id: '1',
    timeRange: '05:00 - 06:00',
    titleEn: 'Awakening & Hydration',
    titleMy: 'နိုးထခြင်းနှင့် ရေသောက်ခြင်း',
    descriptionEn: 'Mindful waking followed by drinking warm water to awaken the internal systems.',
    descriptionMy: 'သတိရှိရှိ နိုးထပြီး ကိုယ်တွင်းအင်္ဂါများ လန်းဆန်းစေရန် ရေနွေးနွေးသောက်ပါ။',
    isCompleted: false,
  },
  {
    id: '2',
    timeRange: '06:00 - 07:30',
