    descriptionEn: '45 minutes of Vipassana meditation followed by reading sacred or philosophical texts.',
    descriptionMy: 'မိနစ် ၄၅ မိနစ်ခန့် ဝိပဿနာ တရားအားထုတ်ပြီးနောက် ဒဿနစာပေများ ဖတ်ရှုပါ။',
    isCompleted: false,
  },
  {
    id: '3',
    timeRange: '07:30 - 08:30',
    titleEn: 'Mindful Movement',
    titleMy: 'သတိရှိရှိ ကိုယ်လက်လှုပ်ရှားခြင်း',
    descriptionEn: 'Yoga, Tai Chi, or walking meditation to integrate wisdom into the body.',
    descriptionMy: 'ယောဂ၊ ထိုက်ချိ (သို့မဟုတ်) စင်္ကြံလျှောက်ခြင်းဖြင့် ခန္ဓာကိုယ်နှင့် စိတ်ကို တစ်သားတည်းဖြစ်စေပါ။',
    isCompleted: false,
  },
  {
    id: '4',
    timeRange: '08:30 - 09:30',
    titleEn: 'Conscious Nourishment',
    titleMy: 'သတိဖြင့် အာဟာရပြုခြင်း',
    descriptionEn: 'A light, healthy breakfast eaten in complete silence.',
    descriptionMy: 'အာဟာရဖြစ်စေမည့် မနက်စာကို ဆိတ်ငြိမ်စွာ စားသုံးပါ။',
    isCompleted: false,
  },
  {
    id: '5',
    timeRange: '09:30 - 12:00',
    titleEn: 'Focused Engagement',
    titleMy: 'အာရုံစူးစိုက် လုပ်ဆောင်ခြင်း',
    descriptionEn: 'Deep work or service performed with a focus on presence and non-attachment.',
    descriptionMy: 'လုပ်ငန်းဆောင်တာများကို လောဘ၊ ဒေါသကင်းစင်စွာဖြင့် အပြည့်အဝ အာရုံစိုက် လုပ်ဆောင်ပါ။',
    isCompleted: false,
  },
];

const STORAGE_KEY = 'mindfulness_morning_phase_data';

const App: React.FC = () => {
  const [state, setState] = useState<MorningState>({
    date: new Date().toLocaleDateString(),
    tasks: INITIAL_TASKS,
    wisdomQuote: '',
    note: ''
  });
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Load data
  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setState(parsed);
        }
      }
    } catch (e) {
      setErrorMessage("Failed to load previous data / ယခင်ဒေတာများကို ပြန်လည်ရယူရန် မအောင်မြင်ပါ။");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const saveToLocalStorage = (newState: MorningState) => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(newState));
      setSuccessMessage("Progress Saved / တိုးတက်မှုကို သိမ်းဆည်းပြီးပါပြီ");
      setTimeout(() => setSuccessMessage(null), 3000);
    } catch (e) {
      setErrorMessage("Failed to save data. Please check storage space. / ဒေတာသိမ်းဆည်းရန် မအောင်မြင်ပါ။ ကျေးဇူးပြု၍ ဖုန်းမှတ်ဉာဏ်ကို စစ်ဆေးပါ။");
    }
  };

  const toggleTask = (id: string) => {
    const updatedTasks = state.tasks.map(t => 
      t.id === id ? { ...t, isCompleted: !t.isCompleted } : t
    );
    const newState = { ...state, tasks: updatedTasks };
    setState(newState);
    saveToLocalStorage(newState);
  };

  const fetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = state.tasks.filter(t => t.isCompleted).length;
    const quote = await generateDailyWisdom(completedCount);
    const newState = { ...state, wisdomQuote: quote };
    setState(newState);
    saveToLocalStorage(newState);
    setLoadingWisdom(false);
  };

  const handleNoteChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setState(prev => ({ ...prev, note: e.target.value }));
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 md:py-12">
      {/* Header Section */}
      <header className="text-center mb-12">
        <h1 className="text-4xl md:text-5xl font-bold deep-teal-text mb-2">
          Morning Phase Tracker
