        <h2 className="text-xl md:text-2xl sage-green-text italic">
          မနက်ခင်း လေ့ကျင့်ခန်း အစီအစဉ် (05:00 - 12:00)
        </h2>
        <div className="mt-4 text-sm text-gray-500 font-semibold tracking-widest uppercase">
          {new Date().toDateString()}
        </div>
      </header>

      {/* Error/Success Toast */}
      {errorMessage && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg z-50 shadow-lg flex items-center gap-3">
          <span>{errorMessage}</span>
          <button onClick={() => setErrorMessage(null)} className="font-bold">×</button>
        </div>
      )}
      {successMessage && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 bg-green-100 border border-green-400 text-green-700 px-4 py-3 rounded-lg z-50 shadow-lg animate-fade-in-down">
          {successMessage}
        </div>
      )}

      {/* Wisdom Section */}
      <section className="bg-white rounded-2xl p-6 md:p-8 shadow-sm border-l-8 border-[#D4AF37] mb-12 relative overflow-hidden">
        <div className="relative z-10">
          <h3 className="text-xs font-bold uppercase tracking-widest text-[#D4AF37] mb-2">Daily Insight / နေ့စဉ်အသိအမြင်</h3>
          {state.wisdomQuote ? (
            <p className="wisdom-text text-xl md:text-2xl text-gray-800 leading-relaxed italic">
              "{state.wisdomQuote}"
            </p>
          ) : (
            <p className="text-gray-400 italic">Generate your morning wisdom to begin... / စတင်ရန် မနက်ခင်းပညာရှိစကားကို ရယူပါ။</p>
          )}
          <button 
            onClick={fetchWisdom}
            disabled={loadingWisdom}
            className="mt-6 px-6 py-2 bg-[#006D77] text-white rounded-full font-semibold hover:bg-[#005a63] transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {loadingWisdom ? (
              <span>Seeking Wisdom... / ရှာဖွေနေပါသည်...</span>
            ) : (
              <span>Generate Wisdom / ပညာရှိစကား ရှာဖွေရန်</span>
            )}
          </button>
        </div>
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <svg width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 8v4l3 3"/></svg>
        </div>
      </section>

      {/* Timeline Section */}
      <section className="space-y-6 mb-12">
        <h3 className="text-2xl font-bold deep-teal-text mb-6 flex items-center gap-2">
          <span className="w-8 h-8 rounded-full bg-[#D4AF37] flex items-center justify-center text-white text-sm">✓</span>
          Morning Tasks / လုပ်ဆောင်ချက်များ
        </h3>
        {state.tasks.map((task) => (
          <div 
            key={task.id}
            className={`group transition-all duration-300 rounded-xl p-5 border-2 ${
              task.isCompleted 
                ? 'bg-white border-green-200 shadow-md' 
                : 'bg-[#F9FAF6] border-gray-100 hover:border-teal-200'
            }`}
          >
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex gap-4">
                <div className="hidden md:block pt-1">
                  <span className="text-sm font-bold text-[#D4AF37] whitespace-nowrap">{task.timeRange}</span>
                </div>
                <div>
                  <div className="md:hidden text-xs font-bold text-[#D4AF37] mb-1">{task.timeRange}</div>
                  <h4 className={`text-lg font-bold ${task.isCompleted ? 'text-gray-400 line-through' : 'text-gray-800'}`}>
                    {task.titleEn}
                  </h4>
                  <h5 className={`text-md ${task.isCompleted ? 'text-gray-300' : 'sage-green-text'}`}>
                    {task.titleMy}
                  </h5>
                  <p className="text-sm text-gray-500 mt-2 max-w-xl">
                    {task.descriptionEn}
                  </p>
                  <p className="text-sm text-gray-400 italic">
                    {task.descriptionMy}
                  </p>
                </div>
              </div>
              <button
                onClick={() => toggleTask(task.id)}
                className={`flex-shrink-0 px-6 py-3 rounded-lg font-bold text-sm transition-all flex items-center justify-center gap-2 min-w-[180px] ${
                  task.isCompleted 
                    ? 'bg-gray-100 text-gray-500 cursor-pointer hover:bg-red-50 hover:text-red-600' 
                    : 'bg-[#006D77] text-white hover:shadow-lg transform hover:-translate-y-0.5'
                }`}
              >
                {task.isCompleted ? (
                   <>
                    <span>Undo / ပြန်ဖျက်ရန်</span>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"/></svg>
                   </>
                ) : (
                  <>
                    <span>Mark Complete / ပြီးစီးကြောင်း မှတ်သားရန်</span>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                  </>
                )}
              </button>
            </div>
          </div>
        ))}
      </section>

      {/* Reflections Section */}
      <section className="bg-white rounded-2xl p-6 md:p-8 shadow-sm">
        <h3 className="text-xl font-bold deep-teal-text mb-4">Morning Reflection / မနက်ခင်း ဆင်ခြင်မှု</h3>
        <textarea
          value={state.note}
          onChange={handleNoteChange}
          placeholder="Enter your observations, mental states, or realizations... / စိတ်အခြေအနေ သို့မဟုတ် သိရှိနားလည်မှုများကို ရေးမှတ်ပါ..."
          className="w-full h-32 p-4 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#006D77] focus:border-transparent outline-none transition-all"
        />
        <div className="mt-4 flex justify-end">
          <button 
            onClick={() => saveToLocalStorage(state)}
            className="bg-[#D4AF37] text-white px-8 py-3 rounded-full font-bold hover:bg-[#b8952c] shadow-md transition-all flex items-center gap-2"
          >
            <span>Save Progress / တိုးတက်မှုကို သိမ်းဆည်းရန်</span>
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4"/></svg>
          </button>
        </div>
      </section>

      {/* Footer info */}
      <footer className="mt-20 text-center pb-12 border-t border-gray-200 pt-8">
        <p className="text-gray-400 text-sm">
          Wisdom-Guided Mindfulness Training © {new Date().getFullYear()}
        </p>
        <p className="text-gray-300 text-xs mt-1">
          Designed for Clarity and Inner Peace / စိတ်ကြည်လင်အေးချမ်းမှုအတွက် ရည်ရွယ်ပါသည်။
        </p>
      </footer>
    </div>
  );
};

export default App;

