import { GoogleGenAI } from "@google/genai";
import { WHAT_PROGRAM_QUOTES, ProgramQuote } from "../data/wisdom";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export interface WisdomResponse {
  quote: ProgramQuote;
  reflectionEn: string;
  reflectionMy: string;
}

export const generateDailyWisdom = async (tasksCompleted: number): Promise<WisdomResponse> => {
  const ai = getAI();

  // Pick a random quote from the program list
  const randomQuote = WHAT_PROGRAM_QUOTES[Math.floor(Math.random() * WHAT_PROGRAM_QUOTES.length)];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a mindfulness guide for "The WHAT Program" (Wisdom Talk). 
      Here is today's core quote from the program: 
      "${randomQuote.textEn}" (${randomQuote.textMy})

      The user has completed ${tasksCompleted} morning tasks. 
      Provide a short, 2-sentence morning guidance/reflection that expands on this quote for today's practice.
      Format your response as:
      EN: [English Reflection]
      MY: [Myanmar Reflection]`,
      config: {
        temperature: 0.5,
      }
    });

    const text = response.text || "";
    const enMatch = text.match(/EN:\s*(.*)/i);
    const myMatch = text.match(/MY:\s*(.*)/i);

    return {
      quote: randomQuote,
      reflectionEn: enMatch ? enMatch[1].trim() : "Observe the natural flow of your breath and mind today.",
      reflectionMy: myMatch ? myMatch[1].trim() : "ယနေ့တွင် သင်၏ ထွက်လေဝင်လေနှင့် စိတ်၏ အစဉ်ကို သတိဖြင့် စောင့်ကြည့်ပါ။"
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      quote: randomQuote,
      reflectionEn: "Focus on the present moment as the foundation of your day.",
      reflectionMy: "ယနေ့၏ အခြေခံအဖြစ် ပစ္စုပ္ပန်တည့်တည့်တွင် အာရုံစိုက်ပါ။"
    };
  }
};

