    }
  }, [lang]);

  const saveToLocalStorage = (updatedTasks: MorningTask[], updatedWisdom: WisdomResponse | null, updatedNote: string) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        wisdom: updatedWisdom,
        note: updatedNote
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
