            className="group flex items-center gap-3 px-10 py-4 bg-[#D4AF37] text-white rounded-2xl font-bold hover:bg-[#b8952c] shadow-lg shadow-amber-50 transition-all active:scale-95"
          >
            <span>{t.logBtn}</span>
            <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7"/></svg>
          </button>
        </div>
      </section>

      <footer className="mt-24 text-center pb-12 opacity-40">
