    namePlaceholder: lang === 'my' ? "သင့်အမည်ကို ရိုက်ထည့်ပါ..." : "Enter your name...",
    title: lang === 'my' ? "မနက်ခင်း တရား" : "Morning Wisdom Phase",
    subtitle: lang === 'my' ? "မနက်ခင်းပိုင်း (05:00 AM - 12:00 PM)" : "Morning Section (5:00 AM to 12:00 PM)",
    audioTitle: lang === 'my' ? "တရားတော်များ အကြိုနာယူရန်" : "Vipassana Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ ဤ ၅ ပိုင်းကို အရင်နာယူပါ" : "Listen to these 5 parts before meditation",
    openDrive: lang === 'my' ? "တရားတော်များ ဖွင့်ရန်" : "Open Audio Folder",
    completed: lang === 'my' ? "နာယူပြီး" : "Heard",
    listenFirst: lang === 'my' ? "အရင်နာယူပါ" : "Listen First",
    begin: lang === 'my' ? "ခရီးစဉ် စတင်ရန်" : "Begin Journey",
    reflection: lang === 'my' ? "လမ်းညွှန်ချက်" : "Guide Reflection",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက် ရယူရန်" : "Generate Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
    discipline: lang === 'my' ? "နေ့စဉ်ကျင့်ဝတ်" : "Daily Discipline",
    undo: lang === 'my' ? "ပြန်ဖျက်ရန်" : "Undo",
    completeTask: lang === 'my' ? "ပြီးစီးကြောင်းမှတ်ရန်" : "Complete",
    journal: lang === 'my' ? "သတိဖြင့် မှတ်သားချက်" : "Mindful Journal",
    journalPlaceholder: lang === 'my' ? "စိတ်၏အခြေအနေကို မှတ်သားပါ..." : "How did your mind move during these practices?...",
    logBtn: lang === 'my' ? "မှတ်တမ်းတင်ရန်" : "Log Progress",
  };

  return (
    <div className={`max-w-4xl mx-auto px-4 py-12 ${lang === 'my' ? 'lang-my' : ''}`}>
