        <div className="bg-white p-1 rounded-2xl shadow-sm flex items-center border border-gray-100">
          <button 
            onClick={() => setLang('my')}
            className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
          >
            မြန်မာ
          </button>
          <button 
            onClick={() => setLang('en')}
            className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
          >
            EN
          </button>
        </div>
      </div>

      <header className="text-center mb-12 fade-content">
        <div className="flex flex-col items-center gap-3 mb-6">
          <div className="px-4 py-1.5 bg-[#D4AF37] text-white text-[10px] font-bold uppercase tracking-widest rounded-full shadow-sm">
            {t.project}
          </div>
        </div>
        <h1 className="text-4xl md:text-5xl font-bold deep-teal-text mb-4 leading-tight">{t.title}</h1>
        <h2 className="text-lg md:text-xl sage-green-text italic font-medium">{t.subtitle}</h2>
      </header>

      {/* Messages */}
      {errorMessage && <div className="fixed top-6 left-1/2 -translate-x-1/2 bg-red-100 border border-red-200 text-red-700 px-6 py-3 rounded-2xl z-50 shadow-xl flex items-center gap-4 animate-bounce">
        <span className="font-semibold">{errorMessage}</span>
        <button onClick={() => setErrorMessage(null)} className="text-xl">×</button>
      </div>}
      {successMessage && <div className="fixed top-6 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-8 py-4 rounded-2xl z-50 shadow-2xl animate-fade-in font-bold">
        {successMessage}
      </div>}

      {/* Name Input Section */}
      <section className="bg-white rounded-[2rem] p-8 mb-12 shadow-sm border border-gray-100 fade-content">
        <div className="flex flex-col md:flex-row md:items-center gap-6">
          <label className="text-lg font-bold deep-teal-text min-w-[80px]">{t.nameLabel} *</label>
          <input 
            type="text" 
            value={userName}
            onChange={(e) => {
              setUserName(e.target.value);
