              <h3 className="text-3xl font-bold mb-2 flex items-center gap-4">
                <svg className="w-10 h-10 text-[#D4AF37]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3"/></svg>
                {t.audioTitle}
              </h3>
              <p className="text-teal-100/70 italic text-lg">{t.audioSubtitle}</p>
            </div>
            <a 
              href={DRIVE_FOLDER_URL} 
              target="_blank" 
              rel="noopener noreferrer"
              className="bg-[#D4AF37] hover:bg-[#b8952c] text-white px-8 py-4 rounded-2xl font-bold transition-all shadow-lg flex items-center gap-3 self-start active:scale-95"
            >
              {t.openDrive}
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
            </a>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
            {audioGuides.map((guide) => (
              <button
                key={guide.id}
                onClick={() => toggleAudio(guide.id)}
                className={`flex flex-col items-center justify-center p-6 rounded-3xl transition-all border-2 ${guide.isCompleted ? 'bg-white/20 border-white/40' : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-[#D4AF37]'}`}
              >
                <div className={`w-12 h-12 rounded-full flex items-center justify-center mb-4 transition-colors ${guide.isCompleted ? 'bg-[#D4AF37] text-white' : 'bg-white/10 text-[#D4AF37]'}`}>
                  {guide.isCompleted ? (
                    <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"/></svg>
                  ) : (
                    <span className="font-bold">{guide.id}</span>
                  )}
                </div>
                <span className="text-[10px] uppercase tracking-widest font-bold opacity-80 mb-1">{lang === 'my' ? 'အပိုင်း' : 'Part'} {guide.id}</span>
                <span className={`text-xs font-semibold ${guide.isCompleted ? 'text-white' : 'text-teal-100'}`}>
                  {guide.isCompleted ? t.completed : (lang === 'my' ? 'နာယူရန်' : 'Listen')}
                </span>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Wisdom Card */}
      <section className="bg-white rounded-[2.5rem] p-8 md:p-12 shadow-xl border-t-8 border-[#D4AF37] mb-12 relative overflow-hidden fade-content">
        <div className="flex items-center justify-between mb-10">
          <span className="text-xs font-bold text-[#D4AF37] tracking-widest uppercase bg-amber-50 px-3 py-1 rounded-lg">
            {wisdom ? (lang === 'my' ? wisdom.quote.categoryMy : wisdom.quote.categoryEn) : t.begin}
          </span>
          {wisdom && <span className="text-[10px] text-gray-300 font-mono">Q-{wisdom.quote.id}</span>}
        </div>

        {wisdom ? (
          <div className="space-y-10">
            <blockquote className="border-l-4 border-gray-100 pl-8 relative py-2">
              <svg className="absolute -top-6 -left-6 w-12 h-12 text-[#D4AF37] opacity-10" fill="currentColor" viewBox="0 0 32 32"><path d="M10 8c-3.3 0-6 2.7-6 6v10h10V14H8c0-1.1.9-2 2-2V8zm14 0c-3.3 0-6 2.7-6 6v10h10V14h-6c0-1.1.9-2 2-2V8z"/></svg>
              <p className="text-2xl md:text-3xl text-gray-800 font-serif leading-relaxed italic">
                {lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}
              </p>
            </blockquote>

            <div className="bg-[#FDFDFD] p-8 rounded-[2rem] border border-teal-50 shadow-inner">
              <h4 className="text-[10px] font-bold uppercase tracking-widest deep-teal-text mb-4 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-[#006D77]"></span>
                {t.reflection}
              </h4>
              <p className="text-gray-700 leading-relaxed text-lg italic font-light">
                {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
              </p>
            </div>
          </div>
        ) : (
          <div className="py-20 text-center">
            <p className="text-gray-400 italic text-xl leading-relaxed">
              {lang === 'my' 
                ? "ခရီးစဉ်ကို စတင်ရန် 'The WHAT Program' တရားတော်မှ ထုတ်နုတ်ချက်တစ်ခုကို ရယူပါ။" 
                : "Invoke a teaching from 'The WHAT Program' to start your mindful journey..."}
            </p>
          </div>
        )}

        <div className="mt-12 flex justify-center">
          <button 
            onClick={handleFetchWisdom}
            disabled={loadingWisdom}
            className="group relative px-10 py-5 bg-[#006D77] text-white rounded-2xl font-bold transition-all hover:bg-[#005a63] hover:scale-105 active:scale-95 disabled:opacity-50 shadow-xl shadow-teal-50"
          >
            <span className="flex items-center gap-4 text-lg">
              {loadingWisdom ? t.seeking : t.genBtn}
              <svg className={`w-6 h-6 ${loadingWisdom ? 'animate-spin' : 'group-hover:rotate-12 transition-transform'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"/></svg>
            </span>
          </button>
        </div>
      </section>

      {/* Task List */}
      <section className="space-y-6 mb-16 fade-content">
        <h3 className="text-2xl font-bold deep-teal-text px-4 flex items-center gap-3">
          <span className="w-2 h-8 bg-[#D4AF37] rounded-full"></span>
          {t.discipline}
        </h3>
        {tasks.map(task => (
          <div key={task.id} className={`p-8 md:p-10 rounded-[2rem] border-2 transition-all duration-500 ${task.isCompleted ? 'bg-white border-green-50 opacity-60 scale-[0.98]' : 'bg-[#FDFDFD] border-gray-50 hover:border-[#D4AF37] hover:shadow-2xl'}`}>
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
              <div className="flex gap-8">
                <div className="hidden md:flex flex-col items-center">
                  <div className="w-0.5 h-16 bg-gray-100 rounded-full mb-3"></div>
                  <div className={`w-5 h-5 rounded-full ${task.isCompleted ? 'bg-green-400' : 'bg-[#D4AF37] shadow-sm'}`}></div>
                </div>
                <div>
                  <h4 className={`text-2xl font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-300' : 'text-gray-800'}`}>
                    {lang === 'my' ? task.titleMy : task.titleEn}
                  </h4>
                  <p className={`mt-3 text-base leading-relaxed ${task.isCompleted ? 'text-gray-200' : 'text-gray-500'}`}>
                    {lang === 'my' ? task.descriptionMy : task.descriptionEn}
                  </p>

                  {/* Contextual Links for Meditation Task */}
                  {task.id === '1' && !task.isCompleted && (
                    <div className="mt-4 flex flex-wrap gap-3">
                      <button 
                        onClick={scrollToAudio}
                        className="flex items-center gap-2 text-xs font-bold text-[#006D77] hover:text-[#D4AF37] transition-colors bg-teal-50 px-3 py-1.5 rounded-lg border border-teal-100"
                      >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.647-3.647a1 1 0 011.15-.277zM13.108 6.035a1 1 0 111.784-.9A8.001 8.001 0 0115 13a1 1 0 01-1.784-.9 6 6 0 000-6.065z"/></svg>
                        {t.listenFirst}
                      </button>
                      <button 
                        onClick={() => { setShowPrepModal(true); setPrepStep(0); }}
                        className="flex items-center gap-2 text-xs font-bold text-[#D4AF37] hover:text-[#006D77] transition-colors bg-amber-50 px-3 py-1.5 rounded-lg border border-amber-100"
                      >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M10 12a2 2 0 100-4 2 2 0 000 4z"/><path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z" clipRule="evenodd"/></svg>
                        {t.prepBtn}
                      </button>
                    </div>
                  )}
                </div>
              </div>
              <button 
                onClick={() => toggleTask(task.id)}
                className={`flex-shrink-0 px-8 py-4 rounded-2xl font-bold text-sm transition-all shadow-sm flex items-center gap-3 ${task.isCompleted ? 'bg-gray-100 text-gray-400 hover:bg-red-50 hover:text-red-500' : 'bg-[#006D77] text-white hover:bg-[#005a63] hover:shadow-xl active:scale-95'}`}
              >
                {task.isCompleted ? (
                  <>
                    {t.undo}
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"/></svg>
                  </>
                ) : (
                  <>
                    {t.completeTask}
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                  </>
                )}
              </button>
            </div>
          </div>
        ))}
      </section>

      {/* Reflection Journal */}
      <section className="bg-white rounded-[3rem] p-10 shadow-sm border border-gray-100 fade-content">
        <h3 className="text-2xl font-bold deep-teal-text mb-8 flex items-center gap-4">
          <svg className="w-8 h-8 text-[#D4AF37]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
          {t.journal}
        </h3>
        <textarea 
          value={note}
          onChange={(e) => {
            setNote(e.target.value);
            saveToLocalStorage(tasks, audioGuides, wisdom, e.target.value, userName);
          }}
          placeholder={t.journalPlaceholder}
          className="w-full h-56 p-8 bg-[#FDFDFD] rounded-[2rem] border border-gray-100 focus:ring-4 focus:ring-teal-50 focus:border-[#006D77] outline-none transition-all mb-8 text-xl text-gray-700 leading-relaxed shadow-inner"
        />
        <div className="flex justify-end">
          <button 
            onClick={() => saveToLocalStorage(tasks, audioGuides, wisdom, note, userName)}
            className="group flex items-center gap-4 px-12 py-5 bg-[#D4AF37] text-white rounded-2xl font-bold hover:bg-[#b8952c] shadow-2xl shadow-amber-100 transition-all active:scale-95"
          >
            <span className="text-lg">{t.logBtn}</span>
            <svg className="w-6 h-6 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7"/></svg>
          </button>
        </div>
      </section>

      {/* Preparation Guide Modal */}
      {showPrepModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-900/40 backdrop-blur-md p-4 animate-fade-in">
          <div className="bg-white rounded-[3rem] w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh]">
            <div className="bg-[#D4AF37] p-8 text-white relative">
              <button 
                onClick={() => setShowPrepModal(false)}
                className="absolute top-6 right-6 p-2 hover:bg-white/20 rounded-full transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-xs font-bold uppercase tracking-[0.2em] mb-2 opacity-80">{t.prepTitle}</h4>
              <div className="flex items-center gap-4">
                <span className="text-4xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-sm bg-white/20 px-3 py-1 rounded-full">{lang === 'my' ? MEDITATION_PREP_QUOTES[prepStep].categoryMy : MEDITATION_PREP_QUOTES[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-10 md:p-14">
              <div className="space-y-8 animate-fade-content" key={prepStep}>
                <blockquote className="border-l-4 border-amber-100 pl-8 relative">
                   <svg className="absolute -top-4 -left-4 w-10 h-10 text-[#D4AF37] opacity-10" fill="currentColor" viewBox="0 0 32 32"><path d="M10 8c-3.3 0-6 2.7-6 6v10h10V14H8c0-1.1.9-2 2-2V8zm14 0c-3.3 0-6 2.7-6 6v10h10V14h-6c0-1.1.9-2 2-2V8z"/></svg>
                   <p className="text-2xl md:text-3xl text-gray-800 font-serif leading-relaxed italic">
                    {lang === 'my' ? MEDITATION_PREP_QUOTES[prepStep].textMy : MEDITATION_PREP_QUOTES[prepStep].textEn}
                   </p>
                </blockquote>
                <div className="flex justify-between items-center pt-8 border-t border-gray-50 text-[10px] text-gray-300 font-mono tracking-widest uppercase">
                  <span>Mindful Prep</span>
                  <span>{MEDITATION_PREP_QUOTES[prepStep].source}</span>
                </div>
              </div>
            </div>

            <div className="p-8 border-t border-gray-50 flex items-center justify-between bg-[#FDFDFD]">
              <div className="flex gap-2">
                {MEDITATION_PREP_QUOTES.map((_, i) => (
                  <div key={i} className={`w-1.5 h-1.5 rounded-full transition-all ${i === prepStep ? 'w-6 bg-[#D4AF37]' : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-4">
                {prepStep > 0 && (
                  <button onClick={prevPrep} className="px-6 py-3 border border-gray-100 rounded-xl text-xs font-bold text-gray-400 hover:text-gray-600 transition-colors uppercase tracking-widest">
                    {t.back}
                  </button>
                )}
                {prepStep < MEDITATION_PREP_QUOTES.length - 1 ? (
                  <button onClick={nextPrep} className="px-8 py-3 bg-[#006D77] text-white rounded-xl text-xs font-bold hover:bg-[#005a63] transition-colors shadow-lg shadow-teal-50 uppercase tracking-widest">
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} className="px-8 py-3 bg-[#D4AF37] text-white rounded-xl text-xs font-bold hover:bg-[#b8952c] transition-colors shadow-lg shadow-amber-50 uppercase tracking-widest">
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-28 text-center pb-16 opacity-30">
        <p className="text-sm tracking-[0.2em] font-bold text-gray-500 uppercase">
          Mindful Project / ဝိပဿနာအခြေခံ သင်တန်း
        </p>
      </footer>
    </div>
  );
};

export default App;

