                </blockquote>
                <div className="flex justify-between items-center pt-8 border-t border-gray-50 text-[10px] text-gray-300 font-mono tracking-widest uppercase">
                  <span>{activeModalType === 'meditation' ? 'Mindful Prep' : 'Heart Bloom'}</span>
                  <span>{currentQuotes[prepStep].source}</span>
                </div>
              </div>
            </div>

            <div className="p-8 border-t border-gray-50 flex items-center justify-between bg-[#FDFDFD]">
              <div className="flex gap-2">
                {currentQuotes.map((_, i) => (
                  <div key={i} className={`w-1.5 h-1.5 rounded-full transition-all ${i === prepStep ? `w-6 ${activeModalType === 'meditation' ? 'bg-[#D4AF37]' : 'bg-[#E63946]'}` : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-4">
                {prepStep > 0 && (
                  <button onClick={prevPrep} className="px-6 py-3 border border-gray-100 rounded-xl text-xs font-bold text-gray-400 hover:text-gray-600 transition-colors uppercase tracking-widest">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button 
                    onClick={nextPrep} 
                    className={`px-8 py-3 ${activeModalType === 'meditation' ? 'bg-[#006D77]' : 'bg-[#E63946]'} text-white rounded-xl text-xs font-bold hover:opacity-90 transition-all shadow-lg uppercase tracking-widest`}
                  >
                    {t.next}
                  </button>
                ) : (
                  <button 
                    onClick={() => setShowPrepModal(false)} 
                    className={`px-8 py-3 ${activeModalType === 'meditation' ? 'bg-[#D4AF37]' : 'bg-[#E63946]'} text-white rounded-xl text-xs font-bold hover:opacity-90 transition-all shadow-lg uppercase tracking-widest`}
                  >
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-28 text-center pb-16 opacity-30">
        <p className="text-sm tracking-[0.2em] font-bold text-gray-500 uppercase">
          Mindful Project / ဝိပဿနာအခြေခံ သင်တန်း
        </p>
      </footer>
    </div>
  );
};

export default App;

