      {errorMessage && <div className="fixed top-6 left-1/2 -translate-x-1/2 bg-red-100 border border-red-200 text-red-700 px-6 py-3 rounded-2xl z-50 shadow-xl flex items-center gap-4 animate-bounce">
        <span className="font-semibold">{errorMessage}</span>
        <button onClick={() => setErrorMessage(null)} className="text-xl">×</button>
      </div>}
      {successMessage && <div className="fixed top-6 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-8 py-4 rounded-2xl z-50 shadow-2xl animate-fade-in font-bold">
        {successMessage}
      </div>}

      {/* Name Input Section */}
      <section className="bg-white rounded-[2rem] p-8 mb-12 shadow-sm border border-gray-100 fade-content">
        <div className="flex flex-col md:flex-row md:items-center gap-6">
          <label className="text-lg font-bold deep-teal-text min-w-[80px]">{t.nameLabel} *</label>
          <input 
            type="text" 
