      </section>

      {/* Reflection Journal */}
      <section className="bg-white rounded-[3rem] p-10 shadow-sm border border-gray-100 fade-content">
        <h3 className="text-2xl font-bold deep-teal-text mb-8 flex items-center gap-4">
          <svg className="w-8 h-8 text-[#D4AF37]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
          {t.journal}
        </h3>
        <textarea 
          value={note}
          onChange={(e) => {
            setNote(e.target.value);
            saveToLocalStorage(tasks, audioGuides, wisdom, e.target.value, userName);
          }}
          placeholder={t.journalPlaceholder}
          className="w-full h-56 p-8 bg-[#FDFDFD] rounded-[2rem] border border-gray-100 focus:ring-4 focus:ring-teal-50 focus:border-[#006D77] outline-none transition-all mb-8 text-xl text-gray-700 leading-relaxed shadow-inner"
        />
        <div className="flex justify-end">
          <button 
            onClick={() => saveToLocalStorage(tasks, audioGuides, wisdom, note, userName)}
            className="group flex items-center gap-4 px-12 py-5 bg-[#D4AF37] text-white rounded-2xl font-bold hover:bg-[#b8952c] shadow-2xl shadow-amber-100 transition-all active:scale-95"
          >
            <span className="text-lg">{t.logBtn}</span>
            <svg className="w-6 h-6 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7"/></svg>
          </button>
        </div>
      </section>

      {/* Preparation Guide Modal */}
      {showPrepModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-900/40 backdrop-blur-md p-4 animate-fade-in">
          <div className="bg-white rounded-[3rem] w-full max-w-2xl overflow-hidden shadow-2xl flex flex-col max-h-[90vh]">
            <div className={`${getModalTheme()} p-8 text-white relative transition-colors duration-500`}>
              <button 
                onClick={() => setShowPrepModal(false)}
                className="absolute top-6 right-6 p-2 hover:bg-white/20 rounded-full transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-xs font-bold uppercase tracking-[0.2em] mb-2 opacity-80">
                {activeModalType === 'meditation' ? t.prepTitle : 
                 activeModalType === 'gratitude' ? t.heartTitle : 
                 activeModalType === 'intention' ? t.intentionTitle : t.eatingTitle}
              </h4>
              <div className="flex items-center gap-4">
                <span className="text-4xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-sm bg-white/20 px-3 py-1 rounded-full">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-10 md:p-14">
              <div className="space-y-8 animate-fade-content" key={`${activeModalType}-${prepStep}`}>
                <blockquote className={`border-l-4 ${getModalTheme().replace('bg-', 'border-')} pl-8 relative`}>
                   <svg className={`absolute -top-4 -left-4 w-10 h-10 ${getQuoteIconColor()} opacity-10`} fill="currentColor" viewBox="0 0 32 32"><path d="M10 8c-3.3 0-6 2.7-6 6v10h10V14H8c0-1.1.9-2 2-2V8zm14 0c-3.3 0-6 2.7-6 6v10h10V14h-6c0-1.1.9-2 2-2V8z"/></svg>
                   <p className="text-2xl md:text-3xl text-gray-800 font-serif leading-relaxed italic">
                    {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                   </p>
                </blockquote>
                <div className="flex justify-between items-center pt-8 border-t border-gray-50 text-[10px] text-gray-300 font-mono tracking-widest uppercase">
                  <span>{activeModalType === 'meditation' ? 'Mindful Prep' : 
                         activeModalType === 'gratitude' ? 'Heart Bloom' : 
                         activeModalType === 'intention' ? 'Intention Core' : 'Body Awareness'}</span>
                  <span>{currentQuotes[prepStep].source}</span>
                </div>
              </div>
            </div>

            <div className="p-8 border-t border-gray-50 flex items-center justify-between bg-[#FDFDFD]">
              <div className="flex gap-2">
                {currentQuotes.map((_, i) => (
                  <div key={i} className={`w-1.5 h-1.5 rounded-full transition-all ${i === prepStep ? `w-6 ${getModalTheme()}` : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-4">
                {prepStep > 0 && (
                  <button onClick={prevPrep} className="px-6 py-3 border border-gray-100 rounded-xl text-xs font-bold text-gray-400 hover:text-gray-600 transition-colors uppercase tracking-widest">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button 
                    onClick={nextPrep} 
                    className={`px-8 py-3 ${getModalTheme()} text-white rounded-xl text-xs font-bold hover:opacity-90 transition-all shadow-lg uppercase tracking-widest`}
                  >
                    {t.next}
                  </button>
                ) : (
                  <button 
                    onClick={() => setShowPrepModal(false)} 
                    className={`px-8 py-3 ${getModalTheme()} text-white rounded-xl text-xs font-bold hover:opacity-90 transition-all shadow-lg uppercase tracking-widest`}
                  >
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="mt-28 text-center pb-16 opacity-30">
        <p className="text-sm tracking-[0.2em] font-bold text-gray-500 uppercase">
          Mindful Project / ဝိပဿနာအခြေခံ သင်တန်း
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface MorningTask {
  id: string;
  timeRange: string;
  titleEn: string;
  titleMy: string;
  descriptionEn: string;
  descriptionMy: string;
  isCompleted: boolean;
}

export interface AudioGuide {
  id: number;
  titleEn: string;
  titleMy: string;
  isCompleted: boolean;
}

export interface MorningState {
  date: string;
  tasks: MorningTask[];
  audioGuides: AudioGuide[];
  wisdomQuote?: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
