  { id: '4', timeRange: '', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times. (Read Sensation Guide first)', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။ (သတိဖြင့် စားသုံးခြင်း လမ်းညွှန်ကို ဖတ်ပါ)', isCompleted: false },
];

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Dhamma Audio Part 1", titleMy: "တရားတော် အပိုင်း (၁)", isCompleted: false },
  { id: 2, titleEn: "Dhamma Audio Part 2", titleMy: "တရားတော် အပိုင်း (၂)", isCompleted: false },
  { id: 3, titleEn: "Dhamma Audio Part 3", titleMy: "တရားတော် အပိုင်း (၃)", isCompleted: false },
  { id: 4, titleEn: "Dhamma Audio Part 4", titleMy: "တရားတော် အပိုင်း (၄)", isCompleted: false },
  { id: 5, titleEn: "Dhamma Audio Part 5", titleMy: "တရားတော် အပိုင်း (၅)", isCompleted: false },
];

const STORAGE_KEY = 'mindful_project_v3';
const LANG_KEY = 'mindfulness_lang_pref';
const DRIVE_FOLDER_URL = "https://drive.google.com/drive/folders/1Shs1vGPm53EDBJMZHAVJeZHkYEqvI4cM?usp=sharing";

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Preparation Guide State
  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  const audioSectionRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
