    switch(activeModalType) {
      case 'meditation': return 'text-[#D4AF37]';
      case 'gratitude': return 'text-[#E63946]';
      case 'intention': return 'text-[#006D77]';
      case 'eating': return 'text-[#828E73]';
      default: return 'text-[#D4AF37]';
    }
  };

  return (
    <div className={`max-w-2xl mx-auto px-4 py-8 md:py-12 ${lang === 'my' ? 'lang-my' : ''}`}>
      {/* Dynamic Header */}
      <div className="flex items-center justify-between mb-8 sticky top-0 z-40 bg-[#EDF1E4]/80 backdrop-blur-md py-2">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-[#006D77] flex items-center justify-center text-white font-bold shadow-lg">
                {progressPercent}%
            </div>
            <div className="hidden sm:block">
                <p className="text-[10px] uppercase tracking-widest font-bold text-gray-400">{t.progress}</p>
                <div className="w-24 h-1.5 bg-gray-200 rounded-full mt-0.5 overflow-hidden">
                    <div className="h-full bg-[#D4AF37] transition-all duration-700" style={{ width: `${progressPercent}%` }}></div>
                </div>
            </div>
        </div>

        <div className="bg-white/50 p-1 rounded-2xl flex items-center shadow-sm border border-white/30 glass-card">
          <button 
            onClick={() => setLang('my')}
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
          >မြန်မာ</button>
          <button 
            onClick={() => setLang('en')}
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
          >EN</button>
        </div>
      </div>

      <header className="text-center mb-10 fade-content">
        <h1 className="text-3xl md:text-4xl font-bold deep-teal-text mb-2 leading-tight">{t.title}</h1>
        <div className="h-1 w-12 bg-[#D4AF37] mx-auto rounded-full opacity-40"></div>
      </header>

      {/* Audio Sanctuary - Optimized for Mobile */}
      <section className="bg-[#006D77] rounded-[2.5rem] p-6 md:p-10 mb-8 text-white shadow-2xl relative overflow-hidden fade-content active-scale">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16"></div>
        <div className="relative z-10">
          <div className="flex items-center justify-between mb-8">
            <div>
              <h3 className="text-xl font-bold">{t.audioTitle}</h3>
              <p className="text-teal-100/60 text-xs italic">{t.audioSubtitle}</p>
            </div>
            <a href={DRIVE_FOLDER_URL} target="_blank" rel="noopener noreferrer" 
               className="bg-[#D4AF37] p-3 rounded-2xl shadow-lg active:scale-90 transition-transform">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
            </a>
          </div>

          <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
            {audioGuides.map((guide) => (
              <button key={guide.id} onClick={() => toggleAudio(guide.id)}
                className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all border-2 ${guide.isCompleted ? 'bg-white/20 border-white/40 shadow-inner' : 'bg-white/5 border-white/10'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center mb-2 text-xs font-bold ${guide.isCompleted ? 'bg-[#D4AF37] text-white' : 'bg-white/10 text-[#D4AF37]'}`}>
                  {guide.isCompleted ? <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"/></svg> : guide.id}
                </div>
                <span className="text-[9px] font-bold opacity-70 truncate w-full text-center px-1">{guide.isCompleted ? t.completed : `Part ${guide.id}`}</span>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Wisdom Card - Mobile Polish */}
      <section className="bg-white rounded-[2rem] p-8 shadow-xl border-t-4 border-[#D4AF37] mb-8 relative fade-content glass-card">
        {wisdom ? (
          <div className="space-y-6">
            <div className="flex items-center justify-between opacity-40">
                <span className="text-[10px] font-bold uppercase tracking-widest">{lang === 'my' ? wisdom.quote.categoryMy : wisdom.quote.categoryEn}</span>
                <span className="text-[9px] font-mono">Q-{wisdom.quote.id}</span>
            </div>
            <p className="text-xl md:text-2xl text-gray-800 font-serif italic leading-relaxed text-center">
                "{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"
            </p>
            <div className="bg-[#FDFDFD] p-5 rounded-2xl border border-teal-50 italic text-sm text-gray-500 text-center">
                {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
            </div>
          </div>
        ) : (
          <div className="py-8 text-center text-gray-400 italic text-sm">
            {lang === 'my' ? "တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် အောက်ပါခလုတ်ကို နှိပ်ပါ။" : "Tap below to receive morning wisdom..."}
          </div>
        )}
        <div className="mt-8 flex justify-center">
          <button onClick={handleFetchWisdom} disabled={loadingWisdom}
            className="px-8 py-3.5 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl hover:shadow-teal-100 transition-all active-scale disabled:opacity-50 flex items-center gap-2">
            {loadingWisdom ? t.seeking : t.genBtn}
            {!loadingWisdom && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
          </button>
        </div>
      </section>

      {/* Task List - Touch Optimized */}
      <section className="space-y-4 mb-16 fade-content">
        <h3 className="text-lg font-bold deep-teal-text px-2 flex items-center gap-2 mb-4">
          <span className="w-1.5 h-6 bg-[#D4AF37] rounded-full"></span>
          {t.discipline}
        </h3>
        {tasks.map(task => (
          <div key={task.id} className={`p-6 rounded-[2rem] border transition-all duration-300 glass-card ${task.isCompleted ? 'bg-white/40 border-green-100 opacity-60' : 'bg-white border-white/20 shadow-sm hover:shadow-md'}`}>
            <div className="flex flex-col gap-4">
              <div className="flex items-start justify-between">
                <div>
                  <h4 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-300' : 'text-gray-800'}`}>
                    {lang === 'my' ? task.titleMy : task.titleEn}
                  </h4>
                  <p className={`mt-2 text-xs leading-relaxed ${task.isCompleted ? 'text-gray-300' : 'text-gray-500'}`}>
                    {lang === 'my' ? task.descriptionMy : task.descriptionEn}
                  </p>
                </div>
                <div className={`w-3 h-3 rounded-full flex-shrink-0 mt-1.5 ${task.isCompleted ? 'bg-green-400' : 'bg-[#D4AF37] shadow-sm'}`}></div>
              </div>

              <div className="flex items-center justify-between gap-2 mt-2">
                <div className="flex gap-2">
                    {!task.isCompleted && task.id === '1' && (
                        <button onClick={() => { setActiveModalType('meditation'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-amber-50 text-[#D4AF37] rounded-xl text-[10px] font-bold border border-amber-100 active-scale">{t.prepBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '2' && (
                        <button onClick={() => { setActiveModalType('intention'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-teal-50 text-[#006D77] rounded-xl text-[10px] font-bold border border-teal-100 active-scale">{t.intentionBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '3' && (
                        <button onClick={() => { setActiveModalType('gratitude'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-red-50 text-red-500 rounded-xl text-[10px] font-bold border border-red-100 active-scale">{t.heartBtn}</button>
                    )}
                    {!task.isCompleted && task.id === '4' && (
                        <button onClick={() => { setActiveModalType('eating'); setShowPrepModal(true); setPrepStep(0); }}
                                className="px-4 py-2 bg-green-50 text-[#828E73] rounded-xl text-[10px] font-bold border border-green-100 active-scale">{t.eatingBtn}</button>
                    )}
                </div>
                <button onClick={() => toggleTask(task.id)}
                  className={`px-6 py-3 rounded-2xl font-bold text-xs transition-all active-scale flex items-center gap-2 ${task.isCompleted ? 'bg-gray-100 text-gray-400' : 'bg-[#006D77] text-white shadow-md'}`}>
                  {task.isCompleted ? t.undo : t.completeTask}
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d={task.isCompleted ? "M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" : "M5 13l4 4L19 7"}/></svg>
                </button>
              </div>
            </div>
          </div>
        ))}
      </section>

      {/* Preparation Guide Modal - Full Screen Mobile */}
      {showPrepModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/40 backdrop-blur-sm animate-fade-in"
             onClick={() => setShowPrepModal(false)}>
          <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh] sm:max-h-[80vh] transition-transform duration-300 translate-y-0"
               onClick={e => e.stopPropagation()}>
            <div className={`${getModalTheme()} p-6 md:p-8 text-white relative transition-colors duration-500`}>
              <button type="button" onClick={() => setShowPrepModal(false)}
                className="absolute top-4 right-4 p-2 hover:bg-white/20 rounded-full transition-colors z-[110]" aria-label="Close">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-[10px] font-bold uppercase tracking-widest mb-1 opacity-70">
                {activeModalType === 'meditation' ? t.prepTitle : activeModalType === 'gratitude' ? t.heartTitle : activeModalType === 'intention' ? t.intentionTitle : t.eatingTitle}
              </h4>
              <div className="flex items-center gap-4">
                <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 md:p-12 scroll-smooth">
              <div className="animate-fade-content" key={`${activeModalType}-${prepStep}`}>
                <blockquote className={`border-l-4 ${getModalTheme().replace('bg-', 'border-')} pl-6 relative`}>
                   <svg className={`absolute -top-3 -left-3 w-8 h-8 ${getQuoteIconColor()} opacity-10`} fill="currentColor" viewBox="0 0 32 32"><path d="M10 8c-3.3 0-6 2.7-6 6v10h10V14H8c0-1.1.9-2 2-2V8zm14 0c-3.3 0-6 2.7-6 6v10h10V14h-6c0-1.1.9-2 2-2V8z"/></svg>
                   <p className="text-xl text-gray-800 font-serif leading-relaxed italic">
                    {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                   </p>
                </blockquote>
                <div className="mt-8 flex justify-end text-[9px] text-gray-300 font-mono uppercase tracking-widest">
                  {currentQuotes[prepStep].source}
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-gray-50 flex items-center justify-between bg-gray-50/50">
              <div className="flex gap-1.5">
                {currentQuotes.slice(0, 10).map((_, i) => (
                  <div key={i} className={`w-1 h-1 rounded-full transition-all ${i === prepStep ? `w-4 ${getModalTheme()}` : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-2">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-4 py-2 border border-gray-200 rounded-xl text-[10px] font-bold text-gray-400 uppercase tracking-widest active-scale">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button onClick={() => setPrepStep(s => s + 1)} 
                    className={`px-6 py-2 ${getModalTheme()} text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale`}>
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} 
                    className={`px-6 py-2 ${getModalTheme()} text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale`}>
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Feedback Toasts */}
      {successMessage && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
          {successMessage}
        </div>
      )}

      <footer className="mt-12 text-center pb-8 opacity-20">
        <p className="text-[10px] tracking-[0.3em] font-bold text-gray-500 uppercase">
          Mindful Project / {new Date().getFullYear()}
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface MorningTask {
  id: string;
  timeRange: string;
  titleEn: string;
  titleMy: string;
  descriptionEn: string;
  descriptionMy: string;
  isCompleted: boolean;
}

export interface AudioGuide {
  id: number;
  titleEn: string;
  titleMy: string;
  url: string;
  isCompleted: boolean;
}

export interface MorningState {
  date: string;
  tasks: MorningTask[];
  audioGuides: AudioGuide[];
  wisdomQuote?: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
import { INTENTION_PREP_QUOTES } from './data/intentionPrep';
import { EATING_PREP_QUOTES } from './data/eatingPrep';

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Dhamma Part 1", titleMy: "တရားတော် (၁)", isCompleted: false, url: "https://docs.google.com/uc?export=open&id=15FdBtFT3av2YtDpsuhvvqrrfFay_NM49" },
  { id: 2, titleEn: "Dhamma Part 2", titleMy: "တရားတော် (၂)", isCompleted: false, url: "https://docs.google.com/uc?export=open&id=1qLev4vw2wbaqaDtarHJtg2pnIPYwOqpo" },
  { id: 3, titleEn: "Dhamma Part 3", titleMy: "တရားတော် (၃)", isCompleted: false, url: "https://docs.google.com/uc?export=open&id=1CN6r3-C-uM_pjuf_g_0BwsHBKlBorYIU" },
  { id: 4, titleEn: "Dhamma Part 4", titleMy: "တရားတော် (၄)", isCompleted: false, url: "https://docs.google.com/uc?export=open&id=1us91ljfszgpp_-KPPwZLUKWlJtr_Ob94" },
  { id: 5, titleEn: "Dhamma Part 5", titleMy: "တရားတော် (၅)", isCompleted: false, url: "https://docs.google.com/uc?export=open&id=1av5LJX4LHL9jjaJLe42SWRlxlL0oItpU" },
];

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '', titleEn: '10 Minutes Meditation', titleMy: '၁၀ မိနစ် တရားထိုင်ပါ', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '', titleEn: 'Notice 10 Intentions', titleMy: 'စေတနာ (၁၀)ခု သတိပြုပါ', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', titleEn: 'Say Thank You (10 Times)', titleMy: 'ကျေးဇူးတင်ပါ အကြိမ် (၁၀)ခါ', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const STORAGE_KEY = 'mindful_project_v3';
const LANG_KEY = 'mindfulness_lang_pref';

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Audio Player State
  const [currentAudio, setCurrentAudio] = useState<AudioGuide | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          const savedAudio = (parsed.audioGuides || INITIAL_AUDIO).map((a: any, i: number) => ({
             ...a,
             url: INITIAL_AUDIO[i].url // Ensure URLs are always fresh
          }));
          setAudioGuides(savedAudio);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
      setErrorMessage(lang === 'my' ? "ဒေတာများ ပြန်လည်ရယူရန် မအောင်မြင်ပါ။" : "Failed to load data.");
    }
  }, [lang]);

  const saveToLocalStorage = (
    updatedTasks: MorningTask[], 
    updatedAudio: AudioGuide[], 
    updatedWisdom: WisdomResponse | null
  ) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        audioGuides: updatedAudio,
        wisdom: updatedWisdom
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
      setSuccessMessage(lang === 'my' ? "သိမ်းဆည်းပြီးပါပြီ" : "Saved Progress");
      setTimeout(() => setSuccessMessage(null), 2000);
    } catch (e) {
      setErrorMessage(lang === 'my' ? "သိမ်းဆည်းရန် နေရာမလုံလောက်ပါ။" : "Storage Error.");
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveToLocalStorage(updated, audioGuides, wisdom);
  };

  const playAudio = (guide: AudioGuide) => {
    if (currentAudio?.id === guide.id) {
      if (isPlaying) {
        audioRef.current?.pause();
        setIsPlaying(false);
      } else {
        audioRef.current?.play();
        setIsPlaying(true);
      }
    } else {
      setCurrentAudio(guide);
      setIsPlaying(true);
      // Mark as completed when first played
      const updated = audioGuides.map(a => a.id === guide.id ? { ...a, isCompleted: true } : a);
      setAudioGuides(updated);
      saveToLocalStorage(tasks, updated, wisdom);
    }
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveToLocalStorage(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const getQuotes = () => {
    switch(activeModalType) {
      case 'meditation': return MEDITATION_PREP_QUOTES;
      case 'gratitude': return GRATITUDE_PREP_QUOTES;
      case 'intention': return INTENTION_PREP_QUOTES;
      case 'eating': return EATING_PREP_QUOTES;
      default: return MEDITATION_PREP_QUOTES;
    }
  };

  const currentQuotes = getQuotes();
  const completedCount = tasks.filter(t => t.isCompleted).length + audioGuides.filter(a => a.isCompleted).length;
  const totalSteps = tasks.length + audioGuides.length;
  const progressPercent = Math.round((completedCount / totalSteps) * 100);

  const t = {
    project: "Mindful Project",
    title: lang === 'my' ? "ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန်" : "Wisdom-Guided Mindfulness",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
