            <div className={`${getModalTheme()} p-6 md:p-8 text-white relative transition-colors duration-500`}>
              <button type="button" onClick={() => setShowPrepModal(false)} className="absolute top-4 right-4 p-2 hover:bg-white/20 rounded-full transition-colors z-[110]" aria-label="Close">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-[10px] font-bold uppercase tracking-widest mb-1 opacity-70">
                {activeModalType === 'meditation' ? t.prepTitle : activeModalType === 'gratitude' ? t.heartTitle : activeModalType === 'intention' ? t.intentionTitle : t.eatingTitle}
              </h4>
              <div className="flex items-center gap-4">
                <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 md:p-12 scroll-smooth">
              <div className="animate-fade-content" key={`${activeModalType}-${prepStep}`}>
                <blockquote className={`border-l-4 ${getModalTheme().replace('bg-', 'border-')} pl-6 relative`}>
                   <svg className={`absolute -top-3 -left-3 w-8 h-8 ${getQuoteIconColor()} opacity-10`} fill="currentColor" viewBox="0 0 32 32"><path d="M10 8c-3.3 0-6 2.7-6 6v10h10V14H8c0-1.1.9-2 2-2V8zm14 0c-3.3 0-6 2.7-6 6v10h10V14h-6c0-1.1.9-2 2-2V8z"/></svg>
                   <p className="text-xl text-gray-800 font-serif leading-relaxed italic">
                    {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                   </p>
                </blockquote>
                <div className="mt-8 flex justify-end text-[9px] text-gray-300 font-mono uppercase tracking-widest">
                  {currentQuotes[prepStep].source}
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-gray-50 flex items-center justify-between bg-gray-50/50">
              <div className="flex gap-1.5">
                {currentQuotes.slice(0, 10).map((_, i) => (
                  <div key={i} className={`w-1 h-1 rounded-full transition-all ${i === prepStep ? `w-4 ${getModalTheme()}` : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-2">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-4 py-2 border border-gray-200 rounded-xl text-[10px] font-bold text-gray-400 uppercase tracking-widest active-scale">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button onClick={() => setPrepStep(s => s + 1)} className={`px-6 py-2 ${getModalTheme()} text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale`}>
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} className={`px-6 py-2 ${getModalTheme()} text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest active-scale`}>
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Feedback Toasts */}
      {successMessage && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
          {successMessage}
        </div>
      )}

      <footer className="mt-12 text-center pb-8 opacity-20">
        <p className="text-[10px] tracking-[0.3em] font-bold text-gray-500 uppercase">
          Mindful Project / {new Date().getFullYear()}
        </p>
      </footer>
    </div>
  );
};

