import React, { useState, useEffect, useRef } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';

const AUDIO_PARTS: AudioGuide[] = [
  { id: 1, titleEn: "Part 1", titleMy: "အပိုင်း ၁", isCompleted: false, url: "15FdBtFT3av2YtDpsuhvvqrrfFay_NM49" },
  { id: 2, titleEn: "Part 2", titleMy: "အပိုင်း ၂", isCompleted: false, url: "1qLev4vw2wbaqaDtarHJtg2pnIPYwOqpo" },
  { id: 3, titleEn: "Part 3", titleMy: "အပိုင်း ၃", isCompleted: false, url: "1CN6r3-C-uM_pjuf_g_0BwsHBKlBorYIU" },
  { id: 4, titleEn: "Part 4", titleMy: "အပိုင်း ၄", isCompleted: false, url: "1us91ljfszgpp_-KPPwZLUKWlJtr_Ob94" },
  { id: 5, titleEn: "Part 5", titleMy: "အပိုင်း ၅", isCompleted: false, url: "1av5LJX4LHL9jjaJLe42SWRlxlL0oItpU" },
];

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '05:00 - 06:00', titleEn: 'Silence & Stillness', titleMy: 'တိတ်ဆိတ်ခြင်းနှင့် ငြိမ်သက်ခြင်း', descriptionEn: 'Sit in silence for 15 minutes to center your mind.', descriptionMy: 'စိတ်ကိုတည်ငြိမ်စေရန် ၁၅ မိနစ်ခန့် တိတ်ဆိတ်စွာ ထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '06:00 - 07:30', titleEn: 'Wisdom Study', titleMy: 'ပညာဗဟုသုတ လေ့လာခြင်း', descriptionEn: 'Read or listen to the provided Dhamma guides.', descriptionMy: 'ပေးထားသော တရားလမ်းညွှန်များကို ဖတ်ရှုခြင်း (သို့) နာယူပါ။', isCompleted: false },
  { id: '3', timeRange: '07:30 - 09:00', titleEn: 'Mindful Movement', titleMy: 'သတိရှိသော လှုပ်ရှားမှု', descriptionEn: 'Perform daily chores with 100% presence.', descriptionMy: 'နေ့စဉ်အလုပ်များကို သတိအပြည့်ဖြင့် လုပ်ဆောင်ပါ။', isCompleted: false },
  { id: '4', timeRange: '09:00 - 11:00', titleEn: 'Clarity of Speech', titleMy: 'ပြောဆိုမှု တည်ကြည်ခြင်း', descriptionEn: 'Practice gentle and truthful communication.', descriptionMy: 'ယဉ်ကျေးမှန်ကန်သော ပြောဆိုဆက်ဆံမှုကို လေ့ကျင့်ပါ။', isCompleted: false },
  { id: '5', timeRange: '11:00 - 12:00', titleEn: 'Gratitude Reflection', titleMy: 'ကျေးဇူးတရား ဆင်ခြင်ခြင်း', descriptionEn: 'Acknowledge three blessings received this morning.', descriptionMy: 'ယနေ့မနက် ရရှိသော ကောင်းချီး ၃ ခုကို အောက်မေ့ပါ။', isCompleted: false },
];

const STORAGE_KEY = 'mindful_wisdom_morning_v1';

const App: React.FC = () => {
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  // Audio Player State
  const [currentAudio, setCurrentAudio] = useState<AudioGuide | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks);
          setWisdom(parsed.wisdom);
        }
      } catch (e) {
        console.error("Failed to parse saved state", e);
      }
    }
  }, []);

  const saveState = (updatedTasks: MorningTask[], updatedWisdom: WisdomResponse | null) => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        wisdom: updatedWisdom
      }));
    } catch (e) {
      setErrorMessage("Failed to save progress. / ဒေတာသိမ်းဆည်းရန် မအောင်မြင်ပါ။");
      setTimeout(() => setErrorMessage(null), 4000);
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveState(updated, wisdom);
  };

  const loadAudio = async (part: AudioGuide) => {
    if (currentAudio?.id === part.id) return;

    setIsAudioLoading(true);
    setCurrentAudio(part);
    setAudioUrl(null);

    const directUrl = `https://drive.google.com/uc?id=${part.url}&export=download`;

    // We set the URL directly, but handle error reporting
    setAudioUrl(directUrl);
    setIsAudioLoading(false);
    setIsPlaying(true);
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completed = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completed);
    setWisdom(result);
    saveState(tasks, result);
    setLoadingWisdom(false);
  };

  const completedCount = tasks.filter(t => t.isCompleted).length;

  return (
    <div className="min-h-screen pb-32">
      <div className="max-w-2xl mx-auto px-4 py-8 md:py-12">

        {/* Header */}
        <header className="text-center mb-12 fade-content">
          <div className="inline-block bg-[#006D77] text-[#D4AF37] px-4 py-1 rounded-full text-xs font-bold mb-4 tracking-widest uppercase">
            Morning Phase / မနက်ခင်းကာလ (5:00 AM - 12:00 PM)
          </div>
          <h1 className="text-4xl md:text-5xl font-bold text-[#006D77] mb-4 leading-tight">
            Wisdom-Guided<br/>Mindfulness
          </h1>
          <p className="text-gray-500 italic">ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန် လေ့ကျင့်ရေး</p>
        </header>

        {/* Audio Sanctuary Section */}
        <section className="bg-[#006D77] rounded-[2.5rem] p-8 mb-10 text-white shadow-2xl relative overflow-hidden fade-content">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16"></div>
          <div className="relative z-10">
            <h2 className="text-2xl font-bold mb-2">Audio Sanctuary</h2>
            <p className="text-teal-100/60 text-sm mb-8">Listen before practice / တရားမကျင့်မီ နာယူပါ</p>

            <div className="flex flex-wrap gap-4 justify-center sm:justify-start">
              {AUDIO_PARTS.map((part) => (
                <button
                  key={part.id}
                  onClick={() => loadAudio(part)}
                  className={`group relative flex flex-col items-center justify-center w-16 h-16 sm:w-20 sm:h-20 rounded-2xl transition-all duration-300 active-scale border-2 ${
                    currentAudio?.id === part.id 
                      ? 'bg-[#D4AF37] border-white text-white' 
                      : 'bg-white/5 border-white/10 text-white hover:bg-white/10'
                  }`}
                >
                  <span className="text-xl font-bold">{part.id}</span>
                  <span className="text-[10px] font-medium opacity-60 uppercase tracking-tighter">Part {part.id}</span>
                  {currentAudio?.id === part.id && isPlaying && (
                    <div className="absolute -bottom-1 w-6 h-1 bg-white rounded-full animate-pulse"></div>
                  )}
                </button>
              ))}
            </div>
          </div>
        </section>

        {/* Inline Audio Player Bar */}
        {currentAudio && (
          <div className="fixed bottom-6 left-4 right-4 z-50 animate-fade-in max-w-xl mx-auto">
            <div className="bg-white rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] border border-gray-100 p-4 flex items-center gap-4 glass-card">
              <div className="w-12 h-12 bg-[#D4AF37] rounded-2xl flex items-center justify-center text-white shadow-lg flex-shrink-0">
                {isAudioLoading ? (
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                ) : (
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg>
                )}
              </div>
              <div className="flex-grow min-w-0">
                <p className="text-[10px] font-bold text-[#D4AF37] uppercase tracking-widest mb-0.5">Now Playing / နာယူနေသည်</p>
                <h4 className="text-sm font-bold text-[#006D77] truncate">{currentAudio.titleEn} - {currentAudio.titleMy}</h4>
              </div>
              <div className="flex items-center gap-2">
                <audio
                  ref={audioRef}
                  src={audioUrl || ''}
                  onPlay={() => setIsPlaying(true)}
                  onPause={() => setIsPlaying(false)}
                  onEnded={() => setIsPlaying(false)}
                  className="hidden"
                  controls
                  autoPlay
                />
                <button 
                  onClick={() => isPlaying ? audioRef.current?.pause() : audioRef.current?.play()}
                  className="w-10 h-10 rounded-full bg-[#EDF1E4] text-[#006D77] flex items-center justify-center active-scale transition-colors"
                >
                  {isPlaying ? (
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
                  ) : (
                    <svg className="w-5 h-5 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                  )}
                </button>
                <button 
                  onClick={() => setCurrentAudio(null)}
                  className="w-10 h-10 rounded-full bg-red-50 text-red-400 flex flex-col items-center justify-center active-scale"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Wisdom Guide */}
        <section className="bg-white rounded-[2rem] p-8 shadow-xl border-t-4 border-[#D4AF37] mb-10 relative fade-content glass-card">
          {wisdom ? (
            <div className="space-y-6">
              <div className="flex items-center justify-between opacity-30">
                <span className="text-[10px] font-bold uppercase tracking-widest">{wisdom.quote.categoryEn}</span>
                <span className="text-[10px] font-bold uppercase tracking-widest">{wisdom.quote.categoryMy}</span>
              </div>
              <p className="text-xl md:text-2xl text-gray-800 font-serif italic leading-relaxed text-center wisdom-text">
                "{wisdom.quote.textEn}"
              </p>
              <p className="text-lg md:text-xl text-gray-600 font-serif italic leading-relaxed text-center lang-my">
                "{wisdom.quote.textMy}"
              </p>
              <div className="bg-[#EDF1E4] p-4 rounded-2xl border border-[#006D77]/5 italic text-sm text-[#006D77]/70 text-center">
                {wisdom.reflectionEn} / {wisdom.reflectionMy}
              </div>
            </div>
          ) : (
            <div className="py-8 text-center text-gray-400 italic text-sm">
              Receive guidance from the Dhamma...<br/>တရားတော်မှ လမ်းညွှန်ချက် ရယူပါ...
            </div>
          )}
          <div className="mt-8 flex justify-center">
            <button
              onClick={handleFetchWisdom}
              disabled={loadingWisdom}
              className="group px-8 py-3.5 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl hover:shadow-[#006D77]/20 transition-all active-scale disabled:opacity-50 flex flex-col items-center gap-1"
            >
              <span>{loadingWisdom ? 'SEEKING... / ရှာဖွေနေသည်...' : 'PROGRAM WISDOM / တရားတော်ထုတ်နုတ်ချက်'}</span>
            </button>
          </div>
        </section>

        {/* Task Tracker */}
        <div className="space-y-4 mb-16 fade-content">
          <div className="flex items-center justify-between px-2 mb-6">
            <h3 className="text-xl font-bold text-[#006D77]">Daily Discipline / နေ့စဉ်ကျင့်ဝတ်</h3>
            <div className="text-xs font-bold text-[#D4AF37] bg-[#D4AF37]/10 px-3 py-1 rounded-full">
              {completedCount} / {tasks.length} COMPLETE
            </div>
          </div>

          {tasks.map((task) => (
            <div 
              key={task.id}
              className={`group p-6 rounded-[2rem] border transition-all duration-300 glass-card ${
                task.isCompleted 
                  ? 'bg-white/40 border-green-100 opacity-60' 
                  : 'bg-white border-white/20 shadow-sm hover:shadow-md'
              }`}
            >
              <div className="flex items-start gap-4">
                <button
                  onClick={() => toggleTask(task.id)}
                  className={`w-12 h-12 rounded-2xl flex flex-shrink-0 items-center justify-center transition-all active-scale ${
                    task.isCompleted ? 'bg-green-500 text-white' : 'bg-[#EDF1E4] text-[#006D77] border-2 border-[#006D77]/10'
                  }`}
                >
                  {task.isCompleted ? (
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
                  ) : (
                    <span className="font-bold">{task.id}</span>
                  )}
                </button>
                <div className="flex-grow">
                  <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-1 mb-2">
                    <h4 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'text-gray-400' : 'text-gray-800'}`}>
                      {task.titleEn} / {task.titleMy}
                    </h4>
                    <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{task.timeRange}</span>
                  </div>
                  <p className={`text-sm leading-relaxed ${task.isCompleted ? 'text-gray-300' : 'text-gray-500'}`}>
                    {task.descriptionEn}<br/>
                    <span className="lang-my">{task.descriptionMy}</span>
                  </p>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Error/Success Messages */}
        {errorMessage && (
          <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-red-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-50 animate-fade-in font-bold text-sm">
            {errorMessage}
          </div>
        )}

        <footer className="mt-20 text-center opacity-30">
          <p className="text-[10px] tracking-[0.4em] font-bold text-gray-500 uppercase mb-2">Mindful Project / 2024</p>
          <p className="text-[9px] text-gray-400">Wisdom Talk Program - Morning Phase</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
