  { id: 2, titleEn: "Dhamma Part 2", titleMy: "တရားတော် (၂)", isCompleted: false, url: "https://drive.google.com/uc?id=1qLev4vw2wbaqaDtarHJtg2pnIPYwOqpo&export=download" },
  { id: 3, titleEn: "Dhamma Part 3", titleMy: "တရားတော် (၃)", isCompleted: false, url: "https://drive.google.com/uc?id=1CN6r3-C-uM_pjuf_g_0BwsHBKlBorYIU&export=download" },
  { id: 4, titleEn: "Dhamma Part 4", titleMy: "တရားတော် (၄)", isCompleted: false, url: "https://drive.google.com/uc?id=1us91ljfszgpp_-KPPwZLUKWlJtr_Ob94&export=download" },
  { id: 5, titleEn: "Dhamma Part 5", titleMy: "တရားတော် (၅)", isCompleted: false, url: "https://drive.google.com/uc?id=1av5LJX4LHL9jjaJLe42SWRlxlL0oItpU&export=download" },
];

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '05:00 - 06:00', titleEn: 'Mindful Meditation', titleMy: 'သတိဖြင့် တရားထိုင်ခြင်း', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '06:00 - 08:00', titleEn: 'Wisdom Integration', titleMy: 'ပညာနှင့် ပေါင်းစပ်ခြင်း', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', timeRange: '08:00 - 10:00', titleEn: 'Gratitude Practice', titleMy: 'ကျေးဇူးတရား ပွားများခြင်း', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', timeRange: '10:00 - 12:00', titleEn: 'Mindful Eating', titleMy: 'သတိဖြင့် စားသုံးခြင်း', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const STORAGE_KEY = 'wisdom_morning_v4';
const LANG_KEY = 'mindfulness_lang_pref';

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Audio Player State
  const [currentAudio, setCurrentAudio] = useState<AudioGuide | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
      setErrorMessage(lang === 'my' ? "ဒေတာများ ပြန်လည်ရယူရန် မအောင်မြင်ပါ။" : "Failed to load data.");
    }
  }, [lang]);

  const saveToLocalStorage = (
    updatedTasks: MorningTask[], 
    updatedAudio: AudioGuide[], 
    updatedWisdom: WisdomResponse | null
  ) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        audioGuides: updatedAudio,
        wisdom: updatedWisdom
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
      setSuccessMessage(lang === 'my' ? "သိမ်းဆည်းပြီးပါပြီ" : "Progress Saved");
      setTimeout(() => setSuccessMessage(null), 2000);
    } catch (e) {
      setErrorMessage(lang === 'my' ? "သိမ်းဆည်းရန် အမှားအယွင်းရှိပါသည်။" : "Failed to save data.");
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveToLocalStorage(updated, audioGuides, wisdom);
  };

  const playAudio = (guide: AudioGuide) => {
    if (currentAudio?.id === guide.id) {
      if (isPlaying) {
        audioRef.current?.pause();
      } else {
        audioRef.current?.play();
      }
    } else {
      setIsAudioLoading(true);
      setCurrentAudio(guide);
      const updated = audioGuides.map(a => a.id === guide.id ? { ...a, isCompleted: true } : a);
      setAudioGuides(updated);
      saveToLocalStorage(tasks, updated, wisdom);
    }
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveToLocalStorage(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const getQuotes = () => {
    switch(activeModalType) {
      case 'meditation': return MEDITATION_PREP_QUOTES;
      case 'gratitude': return GRATITUDE_PREP_QUOTES;
      case 'intention': return INTENTION_PREP_QUOTES;
      case 'eating': return EATING_PREP_QUOTES;
      default: return MEDITATION_PREP_QUOTES;
    }
  };

  const currentQuotes = getQuotes();
  const completedCount = tasks.filter(t => t.isCompleted).length;
  const progressPercent = Math.round((completedCount / tasks.length) * 100);

  const t = {
    title: lang === 'my' ? "ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန်" : "Wisdom-Guided Mindfulness",
    morning: lang === 'my' ? "မနက်ခင်းကာလ (၅:၀၀ - ၁၂:၀၀)" : "Morning Phase (5:00 - 12:00)",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ နာယူပါ" : "Listen before practice",
    nowPlaying: lang === 'my' ? "ယခုဖွင့်နေသည်" : "Now Playing",
    loading: lang === 'my' ? "ဖွင့်နေသည်..." : "Loading...",
    close: lang === 'my' ? "ပိတ်ရန်" : "Close",
    prepBtn: lang === 'my' ? "အကြိုလမ်းညွှန်" : "Prep Guide",
    completeTask: lang === 'my' ? "ပြီးပါပြီ" : "Mark Done",
    undo: lang === 'my' ? "ပြန်ပြင်ရန်" : "Undo",
    discipline: lang === 'my' ? "နေ့စဉ်ကျင့်ဝတ်" : "Daily Discipline",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
    next: lang === 'my' ? "နောက်သို့" : "Next",
    back: lang === 'my' ? "ရှေ့သို့" : "Back",
    progress: lang === 'my' ? "ပြီးစီးမှု" : "Progress",
  };

  return (
    <div className="min-h-screen pb-32">
      <div className={`max-w-2xl mx-auto px-4 py-8 md:py-12 ${lang === 'my' ? 'lang-my' : ''}`}>

        {/* Top Navbar */}
        <div className="flex items-center justify-between mb-8 sticky top-0 z-40 bg-[#EDF1E4]/80 backdrop-blur-md py-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-[#006D77] flex items-center justify-center text-white font-bold shadow-lg">
              {progressPercent}%
            </div>
            <div className="hidden sm:block">
              <p className="text-[10px] uppercase tracking-widest font-bold text-gray-400">{t.progress}</p>
              <div className="w-24 h-1.5 bg-gray-200 rounded-full mt-0.5 overflow-hidden">
                <div className="h-full bg-[#D4AF37] transition-all duration-700" style={{ width: `${progressPercent}%` }}></div>
              </div>
            </div>
          </div>

          <div className="bg-white/50 p-1 rounded-2xl flex items-center shadow-sm border border-white/30">
            <button onClick={() => setLang('my')} className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400'}`}>မြန်မာ</button>
            <button onClick={() => setLang('en')} className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-gray-400'}`}>EN</button>
          </div>
        </div>

        <header className="text-center mb-10 fade-content">
          <h1 className="text-3xl md:text-5xl font-bold text-[#006D77] mb-2 leading-tight">{t.title}</h1>
          <p className="text-[#D4AF37] font-bold text-xs uppercase tracking-widest">{t.morning}</p>
        </header>

        {/* Audio Grid */}
        <section className="bg-[#006D77] rounded-[2.5rem] p-8 mb-8 text-white shadow-2xl relative overflow-hidden fade-content">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16"></div>
          <div className="relative z-10">
            <h3 className="text-xl font-bold mb-1">{t.audioTitle}</h3>
            <p className="text-teal-100/60 text-xs italic mb-6">{t.audioSubtitle}</p>

            <div className="grid grid-cols-5 gap-3">
              {audioGuides.map((guide) => (
                <button 
                  key={guide.id} 
                  onClick={() => playAudio(guide)}
                  className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all border-2 active-scale ${
                    currentAudio?.id === guide.id ? 'bg-[#D4AF37] border-white' : (guide.isCompleted ? 'bg-white/20 border-white/30' : 'bg-white/5 border-white/10')
                  }`}
                >
                  <span className="text-lg font-bold">{guide.id}</span>
                  <span className="text-[9px] uppercase font-bold opacity-60">Part</span>
                </button>
              ))}
            </div>
          </div>
        </section>

        {/* Persistent Player Controls */}
        {currentAudio && (
          <div className="fixed bottom-6 left-4 right-4 z-50 max-w-xl mx-auto animate-fade-in">
            <div className="bg-white rounded-[2rem] shadow-2xl p-4 flex items-center gap-4 border border-white/50 glass-card">
              <button 
                onClick={() => isPlaying ? audioRef.current?.pause() : audioRef.current?.play()}
                className="w-12 h-12 bg-[#006D77] rounded-full flex items-center justify-center text-white flex-shrink-0 active-scale shadow-lg"
              >
                {isAudioLoading ? (
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                ) : isPlaying ? (
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
                ) : (
                  <svg className="w-5 h-5 ml-1" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                )}
              </button>

              <div className="flex-grow min-w-0">
                <p className="text-[10px] font-bold text-[#D4AF37] uppercase tracking-widest">{isAudioLoading ? t.loading : t.nowPlaying}</p>
                <p className="text-sm font-bold text-[#006D77] truncate">{lang === 'my' ? currentAudio.titleMy : currentAudio.titleEn}</p>
              </div>

              <button 
                onClick={() => {
                  audioRef.current?.pause();
                  setCurrentAudio(null);
                }}
                className="w-10 h-10 rounded-full bg-gray-100 text-gray-400 flex flex-col items-center justify-center text-[8px] font-bold uppercase"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                {t.close}
              </button>

              <audio 
                ref={audioRef} 
                src={currentAudio.url} 
                autoPlay
                onPlay={() => setIsPlaying(true)}
                onPause={() => setIsPlaying(false)}
                onLoadedData={() => setIsAudioLoading(false)}
                onError={() => {
                  setErrorMessage(lang === 'my' ? "အသံဖိုင်ဖွင့်၍မရပါ။" : "Audio error.");
                  setIsAudioLoading(false);
                }}
              />
            </div>
          </div>
        )}

        {/* Wisdom Section */}
        <section className="bg-white rounded-[2.5rem] p-8 shadow-xl border-t-4 border-[#D4AF37] mb-10 relative fade-content glass-card">
          {wisdom ? (
            <div className="space-y-6">
              <p className="text-xl md:text-2xl text-gray-800 font-serif italic leading-relaxed text-center">
                "{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"
              </p>
              <div className="bg-[#EDF1E4] p-5 rounded-2xl border border-teal-50 italic text-sm text-[#006D77]/70 text-center leading-relaxed">
                {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
              </div>
            </div>
          ) : (
            <div className="py-8 text-center text-gray-400 italic text-sm">
              Tap below for your morning wisdom...<br/>တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် နှိပ်ပါ။
            </div>
          )}
          <div className="mt-8 flex justify-center">
            <button onClick={handleFetchWisdom} disabled={loadingWisdom}
              className="px-8 py-3.5 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl active-scale disabled:opacity-50 flex items-center gap-3">
              {loadingWisdom ? t.seeking : t.genBtn}
              {!loadingWisdom && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
            </button>
          </div>
        </section>

        {/* Tasks Section */}
        <section className="space-y-4 mb-16 fade-content">
          <h3 className="text-lg font-bold text-[#006D77] px-2 flex items-center gap-2 mb-6">
            <span className="w-1.5 h-6 bg-[#D4AF37] rounded-full"></span>
            {t.discipline}
          </h3>
          {tasks.map(task => (
            <div key={task.id} className={`p-6 rounded-[2rem] border transition-all duration-300 glass-card ${task.isCompleted ? 'bg-white/40 border-green-100 opacity-60' : 'bg-white border-white/20 shadow-sm'}`}>
              <div className="flex flex-col gap-4">
                <div className="flex items-start justify-between">
                  <div>
                    <h4 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-300' : 'text-gray-800'}`}>
                      {lang === 'my' ? task.titleMy : task.titleEn}
                    </h4>
                    <p className={`mt-2 text-xs leading-relaxed ${task.isCompleted ? 'text-gray-300' : 'text-gray-500'}`}>
                      {lang === 'my' ? task.descriptionMy : task.descriptionEn}
                    </p>
                  </div>
                  <span className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">{task.timeRange}</span>
                </div>

                <div className="flex items-center justify-between gap-2">
                  {!task.isCompleted && (
                    <button onClick={() => { 
                      setActiveModalType(task.id === '1' ? 'meditation' : task.id === '2' ? 'intention' : task.id === '3' ? 'gratitude' : 'eating');
                      setShowPrepModal(true); 
                      setPrepStep(0); 
                    }}
                    className="px-4 py-2 rounded-xl text-[10px] font-bold bg-[#D4AF37]/10 text-[#D4AF37] border border-[#D4AF37]/20 active-scale">
                      {t.prepBtn}
                    </button>
                  )}
                  <button onClick={() => toggleTask(task.id)}
                    className={`ml-auto px-6 py-3 rounded-2xl font-bold text-xs transition-all active-scale flex items-center gap-2 ${task.isCompleted ? 'bg-gray-100 text-gray-400' : 'bg-[#006D77] text-white shadow-lg'}`}>
                    {task.isCompleted ? t.undo : t.completeTask}
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d={task.isCompleted ? "M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" : "M5 13l4 4L19 7"}/></svg>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </section>

        {/* Preparation Guide Modal */}
        {showPrepModal && (
          <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/40 backdrop-blur-sm animate-fade-in" onClick={() => setShowPrepModal(false)}>
            <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh] transition-transform duration-300 translate-y-0" onClick={e => e.stopPropagation()}>
              <div className="bg-[#D4AF37] p-8 text-white relative">
                <button onClick={() => setShowPrepModal(false)} className="absolute top-4 right-4 p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
                </button>
                <h4 className="text-[10px] font-bold uppercase tracking-widest mb-1 opacity-70">Guided Instruction / လမ်းညွှန်ချက်</h4>
                <div className="flex items-center gap-4">
                  <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                  <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
                </div>
              </div>

              <div className="flex-grow overflow-y-auto p-8 md:p-12 scroll-smooth">
                <div className="animate-fade-content" key={prepStep}>
                  <blockquote className="border-l-4 border-[#D4AF37] pl-6 relative">
                     <p className="text-xl text-gray-800 font-serif leading-relaxed italic">
                      {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                     </p>
                  </blockquote>
                  <div className="mt-8 flex justify-end text-[9px] text-gray-300 font-mono uppercase tracking-widest">
                    Ref: {currentQuotes[prepStep].source}
                  </div>
                </div>
              </div>

              <div className="p-6 border-t border-gray-50 flex items-center justify-between bg-gray-50">
                <div className="flex gap-1">
                  {currentQuotes.slice(0, 5).map((_, i) => (
                    <div key={i} className={`w-1 h-1 rounded-full transition-all ${i === prepStep ? 'w-4 bg-[#D4AF37]' : 'bg-gray-200'}`}></div>
                  ))}
                </div>
                <div className="flex gap-2">
                  {prepStep > 0 && (
                    <button onClick={() => setPrepStep(s => s - 1)} className="px-5 py-2 border border-gray-200 rounded-xl text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                      {t.back}
                    </button>
                  )}
                  {prepStep < currentQuotes.length - 1 ? (
                    <button onClick={() => setPrepStep(s => s + 1)} className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest">
                      {t.next}
                    </button>
                  ) : (
                    <button onClick={() => setShowPrepModal(false)} className="px-6 py-2 bg-[#D4AF37] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase tracking-widest">
                      {t.close}
                    </button>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Feedback Messages */}
        {successMessage && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
            {successMessage}
          </div>
        )}
        {errorMessage && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-red-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
            {errorMessage}
          </div>
        )}

        <footer className="mt-12 text-center pb-8 opacity-20">
          <p className="text-[10px] tracking-[0.4em] font-bold text-gray-500 uppercase">
            Mindful Project / {new Date().getFullYear()}
          </p>
        </footer>
      </div>
    </div>
  );
};

export default App;

