export interface MorningTask {
  id: string;
  timeRange: string;
  titleEn: string;
  titleMy: string;
  descriptionEn: string;
  descriptionMy: string;
  isCompleted: boolean;
}

// Fixed: Added 'url' property to satisfy the usage in INITIAL_AUDIO and audio player
export interface AudioGuide {
  id: number;
  titleEn: string;
  titleMy: string;
  isCompleted: boolean;
  url: string;
}

export interface MorningState {
  date: string;
  tasks: MorningTask[];
  audioGuides: AudioGuide[];
  wisdomQuote?: string;
}

import { GoogleGenAI } from "@google/genai";
import { WHAT_PROGRAM_QUOTES, ProgramQuote } from "../data/wisdom";

// Initialize GoogleGenAI using the recommended pattern for web applications
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface WisdomResponse {
  quote: ProgramQuote;
  reflectionEn: string;
  reflectionMy: string;
}

export const generateDailyWisdom = async (tasksCompleted: number): Promise<WisdomResponse> => {
  const ai = getAI();

  // Pick a random quote from the program list
  const randomQuote = WHAT_PROGRAM_QUOTES[Math.floor(Math.random() * WHAT_PROGRAM_QUOTES.length)];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a mindfulness guide for "The WHAT Program" (Wisdom Talk). 
      Here is today's core quote from the program: 
      "${randomQuote.textEn}" (${randomQuote.textMy})

      The user has completed ${tasksCompleted} morning tasks. 
      Provide a short, 2-sentence morning guidance/reflection that expands on this quote for today's practice.
      Format your response as:
      EN: [English Reflection]
      MY: [Myanmar Reflection]`,
      config: {
        temperature: 0.5,
      }
    });

    // Access .text property directly as per Gemini API best practices
    const text = response.text || "";
    const enMatch = text.match(/EN:\s*(.*)/i);
    const myMatch = text.match(/MY:\s*(.*)/i);

    return {
      quote: randomQuote,
      reflectionEn: enMatch ? enMatch[1].trim() : "Observe the natural flow of your breath and mind today.",
      reflectionMy: myMatch ? myMatch[1].trim() : "ယနေ့တွင် သင်၏ ထွက်လေဝင်လေနှင့် စိတ်၏ အစဉ်ကို သတိဖြင့် စောင့်ကြည့်ပါ။"
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    return {
      quote: randomQuote,
      reflectionEn: "Focus on the present moment as the foundation of your day.",
      reflectionMy: "ယနေ့၏ အခြေခံအဖြစ် ပစ္စုပ္ပန်တည့်တည့်တွင် အာရုံစိုက်ပါ။"
    };
  }
};

import React, { useState, useEffect } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
import { INTENTION_PREP_QUOTES } from './data/intentionPrep';
import { EATING_PREP_QUOTES } from './data/eatingPrep';

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '05:00 - 06:00', titleEn: '10 Minutes Meditation', titleMy: '၁၀ မိနစ် တရားထိုင်ပါ', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '06:00 - 08:00', titleEn: 'Notice 10 Intentions', titleMy: 'စေတနာ (၁၀)ခု သတိပြုပါ', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', timeRange: '08:00 - 10:00', titleEn: 'Say Thank You (10 Times)', titleMy: 'ကျေးဇူးတင်ပါ အကြိမ် (၁၀)ခါ', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', timeRange: '10:00 - 12:00', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Part 1", titleMy: "အပိုင်း ၁", isCompleted: false, url: "" },
  { id: 2, titleEn: "Part 2", titleMy: "အပိုင်း ၂", isCompleted: false, url: "" },
  { id: 3, titleEn: "Part 3", titleMy: "အပိုင်း ၃", isCompleted: false, url: "" },
  { id: 4, titleEn: "Part 4", titleMy: "အပိုင်း ၄", isCompleted: false, url: "" },
  { id: 5, titleEn: "Part 5", titleMy: "အပိုင်း ၅", isCompleted: false, url: "" },
];

const STORAGE_KEY = 'mindful_project_v5_optimized';
const LANG_KEY = 'mindfulness_lang_pref';
const DRIVE_FOLDER_URL = "https://drive.google.com/drive/folders/1Shs1vGPm53EDBJMZHAVJeZHkYEqvI4cM?usp=sharing";

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
      setErrorMessage(lang === 'my' ? "ဒေတာများ ပြန်လည်ရယူရန် မအောင်မြင်ပါ။" : "Failed to load data.");
    }
  }, [lang]);

  const saveToLocalStorage = (
    updatedTasks: MorningTask[], 
    updatedAudio: AudioGuide[], 
    updatedWisdom: WisdomResponse | null
  ) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        audioGuides: updatedAudio,
        wisdom: updatedWisdom
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
      setSuccessMessage(lang === 'my' ? "သိမ်းဆည်းပြီးပါပြီ" : "Progress Saved");
      setTimeout(() => setSuccessMessage(null), 2000);
    } catch (e) {
      setErrorMessage(lang === 'my' ? "သိမ်းဆည်းရန် နေရာမလုံလောက်ပါ။" : "Storage Error.");
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveToLocalStorage(updated, audioGuides, wisdom);
  };

  const toggleAudio = (id: number) => {
    const updated = audioGuides.map(a => a.id === id ? { ...a, isCompleted: !a.isCompleted } : a);
    setAudioGuides(updated);
    saveToLocalStorage(tasks, updated, wisdom);
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveToLocalStorage(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const getQuotes = () => {
    switch(activeModalType) {
      case 'meditation': return MEDITATION_PREP_QUOTES;
      case 'gratitude': return GRATITUDE_PREP_QUOTES;
      case 'intention': return INTENTION_PREP_QUOTES;
      case 'eating': return EATING_PREP_QUOTES;
      default: return MEDITATION_PREP_QUOTES;
    }
  };

  const currentQuotes = getQuotes();
  const completedCount = tasks.filter(t => t.isCompleted).length;
  const progressPercent = Math.round((completedCount / tasks.length) * 100);

  const t = {
    title: lang === 'my' ? "ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန်" : "Wisdom-Guided Mindfulness",
    morning: lang === 'my' ? "မနက်ခင်းကာလ (၅:၀၀ - ၁၂:၀၀)" : "Morning Phase (5:00 - 12:00)",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ နာယူပါ" : "Listen before practice",
    prepBtn: lang === 'my' ? "အကြိုလမ်းညွှန်" : "Prep Guide",
    completeTask: lang === 'my' ? "ပြီးပါပြီ" : "Mark Done",
    undo: lang === 'my' ? "ပြန်ပြင်ရန်" : "Undo",
    discipline: lang === 'my' ? "နေ့စဉ်ကျင့်ဝတ်" : "Daily Discipline",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
    next: lang === 'my' ? "နောက်သို့" : "Next",
    back: lang === 'my' ? "ရှေ့သို့" : "Back",
    progress: lang === 'my' ? "ပြီးစီးမှု" : "Progress",
    close: lang === 'my' ? "ပိတ်ရန်" : "Close",
  };

  return (
    <div className={`max-w-2xl mx-auto px-4 py-8 md:py-12 ${lang === 'my' ? 'lang-my' : ''}`}>

      {/* Dynamic Header */}
      <nav className="flex items-center justify-between mb-8 sticky top-0 z-40 bg-[#EDF1E4]/90 backdrop-blur-md py-4 border-b border-[#006D77]/5">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-[#006D77] flex items-center justify-center text-white font-bold shadow-lg" aria-label={`Progress: ${progressPercent}%`}>
            {progressPercent}%
          </div>
          <div className="hidden sm:block">
            <p className="text-[10px] uppercase tracking-widest font-bold text-gray-500">{t.progress}</p>
            <div className="w-24 h-1.5 bg-gray-200 rounded-full mt-0.5 overflow-hidden">
              <div className="h-full bg-[#D4AF37] transition-all duration-700" style={{ width: `${progressPercent}%` }}></div>
            </div>
          </div>
        </div>

        <div className="bg-white/50 p-1 rounded-2xl flex items-center shadow-sm border border-white/30 glass-card">
          <button 
            onClick={() => setLang('my')} 
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white shadow-md' : 'text-[#4A5568] hover:bg-gray-100'}`}
            aria-pressed={lang === 'my'}
          >မြန်မာ</button>
          <button 
            onClick={() => setLang('en')} 
            className={`px-4 py-1.5 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white shadow-md' : 'text-[#4A5568] hover:bg-gray-100'}`}
            aria-pressed={lang === 'en'}
          >EN</button>
        </div>
      </nav>

      <header className="text-center mb-10 fade-content">
        <h1 className="text-3xl md:text-5xl font-bold text-[#006D77] mb-2 leading-tight">{t.title}</h1>
        <p className="text-[#D4AF37] font-bold text-xs uppercase tracking-widest">{t.morning}</p>
      </header>

      {/* Audio Grid - Optimized for Core Web Vitals */}
      <section className="bg-[#006D77] rounded-[2.5rem] p-8 mb-8 text-white shadow-2xl relative overflow-hidden fade-content glass-card">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -mr-16 -mt-16"></div>
        <div className="relative z-10">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-xl font-bold">{t.audioTitle}</h2>
              <p className="text-teal-100/70 text-xs italic">{t.audioSubtitle}</p>
            </div>
            <a 
              href={DRIVE_FOLDER_URL} 
              target="_blank" 
              rel="noopener noreferrer" 
              className="bg-[#D4AF37] p-3 rounded-2xl shadow-lg active-scale transition-transform"
              aria-label="Open Audio Folder in Google Drive"
            >
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
            </a>
          </div>

          <div className="grid grid-cols-5 gap-3">
            {audioGuides.map((guide) => (
              <button 
                key={guide.id} 
                onClick={() => toggleAudio(guide.id)}
                className={`flex flex-col items-center justify-center py-4 rounded-2xl transition-all border-2 active-scale ${
                  guide.isCompleted ? 'bg-white/20 border-white/30' : 'bg-white/5 border-white/10'
                }`}
                aria-label={`Toggle Audio Part ${guide.id}`}
              >
                <span className="text-lg font-bold">{guide.id}</span>
                <span className="text-[9px] uppercase font-bold opacity-60">Part</span>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* Wisdom Section - Semantic Layout */}
      <section className="bg-white rounded-[2.5rem] p-8 shadow-xl border-t-4 border-[#D4AF37] mb-10 relative fade-content glass-card">
        <h2 className="sr-only">Morning Wisdom</h2>
        {wisdom ? (
          <article className="space-y-6">
            <p className="text-xl md:text-2xl text-gray-800 font-serif italic leading-relaxed text-center">
              "{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"
            </p>
            <div className="bg-[#EDF1E4] p-5 rounded-2xl border border-teal-50 italic text-sm text-[#006D77] text-center leading-relaxed">
              {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
            </div>
          </article>
        ) : (
          <div className="py-8 text-center text-gray-500 italic text-sm">
            တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် အောက်ပါခလုတ်ကို နှိပ်ပါ။<br/>Tap below for your morning wisdom.
          </div>
        )}
        <div className="mt-8 flex justify-center">
          <button onClick={handleFetchWisdom} disabled={loadingWisdom}
            className="px-8 py-3.5 bg-[#006D77] text-white rounded-2xl font-bold text-sm shadow-xl active-scale disabled:opacity-50 flex items-center gap-3">
            {loadingWisdom ? t.seeking : t.genBtn}
            {!loadingWisdom && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
          </button>
        </div>
      </section>

      {/* Tasks Section - Accessibility Landmark */}
      <section className="space-y-4 mb-16 fade-content">
        <h2 className="text-lg font-bold text-[#006D77] px-2 flex items-center gap-2 mb-6">
          <span className="w-1.5 h-6 bg-[#D4AF37] rounded-full"></span>
          {t.discipline}
        </h2>
        {tasks.map(task => (
          <div key={task.id} className={`p-6 rounded-[2rem] border transition-all duration-300 glass-card ${task.isCompleted ? 'bg-white/40 border-green-100 opacity-60' : 'bg-white border-white/20 shadow-sm'}`}>
            <div className="flex flex-col gap-4">
              <div className="flex items-start justify-between">
                <div>
                  <h3 className={`text-lg font-bold leading-tight ${task.isCompleted ? 'line-through text-gray-300' : 'text-gray-800'}`}>
                    {lang === 'my' ? task.titleMy : task.titleEn}
                  </h3>
                  <p className={`mt-2 text-xs leading-relaxed ${task.isCompleted ? 'text-gray-300' : 'text-gray-600'}`}>
                    {lang === 'my' ? task.descriptionMy : task.descriptionEn}
                  </p>
                </div>
                <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{task.timeRange}</span>
              </div>

              <div className="flex items-center justify-between gap-2">
                {!task.isCompleted && (
                  <button onClick={() => { 
                    setActiveModalType(task.id === '1' ? 'meditation' : task.id === '2' ? 'intention' : task.id === '3' ? 'gratitude' : 'eating');
                    setShowPrepModal(true); 
                    setPrepStep(0); 
                  }}
                  className="px-4 py-2 rounded-xl text-[10px] font-bold bg-[#D4AF37]/10 text-[#B8962F] border border-[#D4AF37]/20 active-scale"
                  aria-label={`Open Preparation Guide for ${task.titleEn}`}
                  >
                    {t.prepBtn}
                  </button>
                )}
                <button onClick={() => toggleTask(task.id)}
                  className={`ml-auto px-6 py-3 rounded-2xl font-bold text-xs transition-all active-scale flex items-center gap-2 ${task.isCompleted ? 'bg-gray-100 text-gray-500' : 'bg-[#006D77] text-white shadow-lg'}`}
                  aria-label={task.isCompleted ? t.undo : t.completeTask}
                  >
                  {task.isCompleted ? t.undo : t.completeTask}
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" aria-hidden="true"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d={task.isCompleted ? "M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" : "M5 13l4 4L19 7"}/></svg>
                </button>
              </div>
            </div>
          </div>
        ))}
      </section>

      {/* Modal - Improved Accessibility Focus/Landmarks */}
      {showPrepModal && (
        <div 
          className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/50 backdrop-blur-sm animate-fade-in" 
          onClick={() => setShowPrepModal(false)}
          role="dialog"
          aria-modal="true"
        >
          <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh] transition-transform duration-300" onClick={e => e.stopPropagation()}>
            <div className="bg-[#D4AF37] p-8 text-white relative">
              <button 
                onClick={() => setShowPrepModal(false)} 
                className="absolute top-4 right-4 p-2 bg-white/10 rounded-full hover:bg-white/20 transition-colors"
                aria-label="Close Guide"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-[10px] font-bold uppercase tracking-widest mb-1 opacity-80">Guided Instruction</h4>
              <div className="flex items-center gap-4">
                <span className="text-3xl font-serif italic">Step {prepStep + 1}</span>
                <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 md:p-12 scroll-smooth">
              <div className="animate-fade-content" key={prepStep}>
                <blockquote className="border-l-4 border-[#D4AF37] pl-6 relative">
                   <p className="text-xl text-gray-800 font-serif leading-relaxed italic">
                    {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                   </p>
                </blockquote>
                <div className="mt-8 flex justify-end text-[9px] text-gray-400 font-mono uppercase tracking-widest">
                  Ref: {currentQuotes[prepStep].source}
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-gray-100 flex items-center justify-between bg-gray-50">
              <div className="flex gap-1" aria-hidden="true">
                {currentQuotes.slice(0, 5).map((_, i) => (
                  <div key={i} className={`w-1 h-1 rounded-full transition-all ${i === prepStep ? 'w-4 bg-[#D4AF37]' : 'bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-2">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-5 py-2 border border-gray-200 rounded-xl text-[10px] font-bold text-gray-500 uppercase active-scale">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button onClick={() => setPrepStep(s => s + 1)} className="px-6 py-2 bg-[#006D77] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase active-scale">
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} className="px-6 py-2 bg-[#D4AF37] text-white rounded-xl text-[10px] font-bold shadow-lg uppercase active-scale">
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Messages */}
      {successMessage && (
        <div role="status" className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
          {successMessage}
        </div>
      )}
      {errorMessage && (
        <div role="alert" className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-red-600 text-white px-6 py-3 rounded-2xl shadow-2xl z-[200] animate-fade-in font-bold text-xs">
          {errorMessage}
        </div>
      )}

      <footer className="mt-12 text-center pb-8 opacity-40">
        <p className="text-[10px] tracking-[0.4em] font-bold text-gray-500 uppercase">
          MINDFUL PROJECT / {new Date().getFullYear()}
        </p>
      </footer>
    </div>
  );
};

export default App;

export interface MorningTask {
  id: string;
  timeRange: string;
  titleEn: string;
  titleMy: string;
  descriptionEn: string;
  descriptionMy: string;
  isCompleted: boolean;
}

export interface AudioGuide {
  id: number;
  titleEn: string;
  titleMy: string;
  isCompleted: boolean;
  url?: string;
}

export interface MorningState {
  date: string;
  tasks: MorningTask[];
  audioGuides: AudioGuide[];
  wisdomQuote?: string;
}

import React, { useState, useEffect } from 'react';
import { MorningTask, AudioGuide } from './types';
import { generateDailyWisdom, WisdomResponse } from './services/gemini';
import { MEDITATION_PREP_QUOTES } from './data/meditationPrep';
import { GRATITUDE_PREP_QUOTES } from './data/gratitudePrep';
import { INTENTION_PREP_QUOTES } from './data/intentionPrep';
import { EATING_PREP_QUOTES } from './data/eatingPrep';

const INITIAL_TASKS: MorningTask[] = [
  { id: '1', timeRange: '05:00 - 06:00', titleEn: '10 Minutes Meditation', titleMy: '၁၀ မိနစ် တရားထိုင်ပါ', descriptionEn: 'Sit in a comfortable place and focus on the present moment.', descriptionMy: 'အဆင်ပြေမည့်နေရာတွင် တရားထိုင်ပါ။', isCompleted: false },
  { id: '2', timeRange: '06:00 - 08:00', titleEn: 'Notice 10 Intentions', titleMy: 'စေတနာ (၁၀)ခု သတိပြုပါ', descriptionEn: 'Observe the intention behind 10 different actions this morning.', descriptionMy: 'မနက်ခင်း လုပ်ဆောင်ချက် ၁၀ ခု၏ နောက်ကွယ်မှ စေတနာကို သတိပြုကြည့်ပါ။', isCompleted: false },
  { id: '3', timeRange: '08:00 - 10:00', titleEn: 'Say Thank You (10 Times)', titleMy: 'ကျေးဇူးတင်ပါ အကြိမ် (၁၀)ခါ', descriptionEn: 'Express gratitude internally or externally 10 times.', descriptionMy: 'စိတ်ထဲမှဖြစ်စေ၊ နှုတ်မှဖြစ်စေ ကျေးဇူးတင်ကြောင်း ၁၀ ကြိမ် ဖော်ပြပါ။', isCompleted: false },
  { id: '4', timeRange: '10:00 - 12:00', titleEn: '10 Mindful Eating Checks', titleMy: 'စားချိန်မှာ သတိ (၁၀) ကြိမ်ပါ', descriptionEn: 'Stay mindful during breakfast/snacks at least 10 times.', descriptionMy: 'အစားစားချိန်တွင် သတိကပ်၍ စားသုံးမှုကို ၁၀ ကြိမ်ခန့် သတိပြုပါ။', isCompleted: false },
];

const INITIAL_AUDIO: AudioGuide[] = [
  { id: 1, titleEn: "Part 1", titleMy: "အပိုင်း ၁", isCompleted: false },
  { id: 2, titleEn: "Part 2", titleMy: "အပိုင်း ၂", isCompleted: false },
  { id: 3, titleEn: "Part 3", titleMy: "အပိုင်း ၃", isCompleted: false },
  { id: 4, titleEn: "Part 4", titleMy: "အပိုင်း ၄", isCompleted: false },
  { id: 5, titleEn: "Part 5", titleMy: "အပိုင်း ၅", isCompleted: false },
];

const STORAGE_KEY = 'mindful_project_pdf_v1';
const LANG_KEY = 'mindfulness_lang_pref';
const DRIVE_FOLDER_URL = "https://drive.google.com/drive/folders/1Shs1vGPm53EDBJMZHAVJeZHkYEqvI4cM?usp=sharing";

type Language = 'my' | 'en';
type ModalType = 'meditation' | 'gratitude' | 'intention' | 'eating';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem(LANG_KEY) as Language) || 'my';
  });
  const [tasks, setTasks] = useState<MorningTask[]>(INITIAL_TASKS);
  const [audioGuides, setAudioGuides] = useState<AudioGuide[]>(INITIAL_AUDIO);
  const [wisdom, setWisdom] = useState<WisdomResponse | null>(null);
  const [loadingWisdom, setLoadingWisdom] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [showPrepModal, setShowPrepModal] = useState(false);
  const [activeModalType, setActiveModalType] = useState<ModalType>('meditation');
  const [prepStep, setPrepStep] = useState(0);

  useEffect(() => {
    localStorage.setItem(LANG_KEY, lang);
  }, [lang]);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed.date === new Date().toLocaleDateString()) {
          setTasks(parsed.tasks || INITIAL_TASKS);
          setAudioGuides(parsed.audioGuides || INITIAL_AUDIO);
          setWisdom(parsed.wisdom || null);
        }
      }
    } catch (e) {
      setErrorMessage(lang === 'my' ? "ဒေတာများ ပြန်လည်ရယူရန် မအောင်မြင်ပါ။" : "Failed to load data.");
    }
  }, [lang]);

  const saveToLocalStorage = (
    updatedTasks: MorningTask[], 
    updatedAudio: AudioGuide[], 
    updatedWisdom: WisdomResponse | null
  ) => {
    try {
      const stateToSave = {
        date: new Date().toLocaleDateString(),
        tasks: updatedTasks,
        audioGuides: updatedAudio,
        wisdom: updatedWisdom
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(stateToSave));
      setSuccessMessage(lang === 'my' ? "သိမ်းဆည်းပြီးပါပြီ" : "Progress Saved");
      setTimeout(() => setSuccessMessage(null), 2000);
    } catch (e) {
      setErrorMessage(lang === 'my' ? "သိမ်းဆည်းရန် နေရာမလုံလောက်ပါ။" : "Storage Error.");
    }
  };

  const toggleTask = (id: string) => {
    const updated = tasks.map(t => t.id === id ? { ...t, isCompleted: !t.isCompleted } : t);
    setTasks(updated);
    saveToLocalStorage(updated, audioGuides, wisdom);
  };

  const toggleAudio = (id: number) => {
    const updated = audioGuides.map(a => a.id === id ? { ...a, isCompleted: !a.isCompleted } : a);
    setAudioGuides(updated);
    saveToLocalStorage(tasks, updated, wisdom);
  };

  const handleFetchWisdom = async () => {
    setLoadingWisdom(true);
    const completedCount = tasks.filter(t => t.isCompleted).length;
    const result = await generateDailyWisdom(completedCount);
    setWisdom(result);
    saveToLocalStorage(tasks, audioGuides, result);
    setLoadingWisdom(false);
  };

  const currentQuotes = (() => {
    switch(activeModalType) {
      case 'meditation': return MEDITATION_PREP_QUOTES;
      case 'gratitude': return GRATITUDE_PREP_QUOTES;
      case 'intention': return INTENTION_PREP_QUOTES;
      case 'eating': return EATING_PREP_QUOTES;
      default: return MEDITATION_PREP_QUOTES;
    }
  })();

  const completedCount = tasks.filter(t => t.isCompleted).length;
  const progressPercent = Math.round((completedCount / tasks.length) * 100);

  const t = {
    title: lang === 'my' ? "ပညာဖြင့် လမ်းညွှန်သော သတိပဋ္ဌာန်" : "Wisdom-Guided Mindfulness",
    morning: lang === 'my' ? "မနက်ခင်းကာလ (၅:၀၀ - ၁၂:၀၀)" : "Morning Phase (5:00 - 12:00)",
    audioTitle: lang === 'my' ? "တရားတော်များ နာယူရန်" : "Audio Sanctuary",
    audioSubtitle: lang === 'my' ? "တရားမထိုင်မီ နာယူပါ" : "Listen before practice",
    prepBtn: lang === 'my' ? "တရားအကြိုလမ်းညွှန်" : "Prep Guide",
    completeTask: lang === 'my' ? "ပြီးပါပြီ" : "Mark Done",
    undo: lang === 'my' ? "ပြန်ပြင်ရန်" : "Undo",
    discipline: lang === 'my' ? "နေ့စဉ်ကျင့်ဝတ်" : "Daily Discipline",
    genBtn: lang === 'my' ? "တရားတော်မှ ထုတ်နုတ်ချက်" : "Program Wisdom",
    seeking: lang === 'my' ? "ရှာဖွေနေသည်..." : "Seeking...",
    next: lang === 'my' ? "နောက်သို့" : "Next",
    back: lang === 'my' ? "ရှေ့သို့" : "Back",
    progress: lang === 'my' ? "ပြီးစီးမှု" : "Progress",
    close: lang === 'my' ? "ပိတ်ရန်" : "Close",
  };

  return (
    <div className={`max-w-xl mx-auto px-6 py-10 md:py-16 ${lang === 'my' ? 'lang-my' : ''}`}>

      {/* Top Navigation - Matching PDF Header Layout */}
      <nav className="flex items-center justify-between mb-12">
        <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-full shadow-sm">
          <span className="text-sm font-bold text-[#006D77]">{progressPercent}%</span>
          <span className="text-[11px] font-bold text-gray-400 uppercase tracking-tight">{t.progress}</span>
        </div>

        <div className="bg-white p-1 rounded-2xl flex items-center shadow-sm border border-gray-100">
          <button 
            onClick={() => setLang('my')} 
            className={`px-5 py-2 rounded-xl text-xs font-bold transition-all ${lang === 'my' ? 'bg-[#006D77] text-white' : 'text-gray-400'}`}
          >မြန်မာ</button>
          <button 
            onClick={() => setLang('en')} 
            className={`px-5 py-2 rounded-xl text-xs font-bold transition-all ${lang === 'en' ? 'bg-[#006D77] text-white' : 'text-gray-400'}`}
          >EN</button>
        </div>
      </nav>

      {/* Main Title */}
      <header className="text-center mb-12 fade-content">
        <h1 className="text-4xl md:text-5xl font-bold text-[#006D77] leading-tight mb-2">
          {t.title}
        </h1>
      </header>

      {/* Audio Selection Section - White Card Grid */}
      <section className="bg-white rounded-[2.5rem] p-8 mb-8 shadow-xl shadow-gray-200/50 fade-content relative overflow-hidden">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-xl font-bold text-gray-400">{t.audioTitle}</h2>
            <p className="text-gray-300 text-xs italic mt-0.5">{t.audioSubtitle}</p>
          </div>
          <a 
            href={DRIVE_FOLDER_URL} 
            target="_blank" 
            rel="noopener noreferrer" 
            className="w-10 h-10 bg-white border border-gray-100 rounded-2xl shadow-sm flex items-center justify-center active-scale"
            aria-label="Open Drive"
          >
            <svg className="w-4 h-4 text-gray-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"/></svg>
          </a>
        </div>

        <div className="grid grid-cols-5 gap-4">
          {audioGuides.map((guide) => (
            <button 
              key={guide.id} 
              onClick={() => toggleAudio(guide.id)}
              className={`flex flex-col items-center justify-center py-5 rounded-2xl transition-all active-scale ${
                guide.isCompleted ? 'bg-[#006D77] text-white' : 'bg-transparent border-transparent text-gray-400'
              }`}
            >
              <span className="text-lg font-bold">{guide.id}</span>
              <span className="text-[10px] font-bold opacity-60 mt-1">Part {guide.id}</span>
            </button>
          ))}
        </div>
      </section>

      {/* Wisdom Section - Gold Border Box */}
      <section className="rounded-[2.5rem] border-2 border-[#D4AF37] p-10 mb-12 fade-content relative min-h-[180px] flex flex-col items-center justify-center text-center">
        {wisdom ? (
          <article className="animate-fade-in">
            <p className="text-xl md:text-2xl text-gray-800 font-serif italic leading-relaxed mb-6">
              "{lang === 'my' ? wisdom.quote.textMy : wisdom.quote.textEn}"
            </p>
            <div className="text-sm text-[#006D77] font-medium max-w-sm mx-auto leading-relaxed">
              {lang === 'my' ? wisdom.reflectionMy : wisdom.reflectionEn}
            </div>
          </article>
        ) : (
          <p className="text-gray-400 text-sm italic max-w-[200px] leading-relaxed">
            တရားတော်မှ လမ်းညွှန်ချက်ရယူရန် အောက်ပါခလုတ်ကို နှိပ်ပါ။
          </p>
        )}

        <div className="absolute -bottom-6 left-1/2 -translate-x-1/2">
          <button 
            onClick={handleFetchWisdom} 
            disabled={loadingWisdom}
            className="bg-white px-10 py-4 rounded-full shadow-lg border border-gray-100 font-bold text-xs text-gray-400 active-scale disabled:opacity-50 transition-all flex items-center gap-3"
          >
            {loadingWisdom ? t.seeking : t.genBtn}
          </button>
        </div>
      </section>

      {/* Daily Discipline - White Cards with Progress Rings */}
      <section className="space-y-6 mb-20 fade-content">
        <h2 className="text-2xl font-bold text-[#006D77] mb-8">{t.discipline}</h2>
        {tasks.map(task => (
          <div key={task.id} className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-gray-50 relative group">
            {/* Task Progress Indicator */}
            <div className={`absolute top-8 right-8 w-6 h-6 rounded-full border-2 transition-all duration-500 ${task.isCompleted ? 'bg-[#006D77] border-[#006D77]' : 'border-gray-50'}`}>
              {task.isCompleted && <svg className="w-full h-full text-white p-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>}
            </div>

            <div className="pr-12">
              <h3 className={`text-2xl font-bold leading-tight mb-3 ${task.isCompleted ? 'text-gray-300' : 'text-gray-800'}`}>
                {lang === 'my' ? task.titleMy : task.titleEn}
              </h3>
              <p className={`text-sm leading-relaxed mb-8 ${task.isCompleted ? 'text-gray-200' : 'text-gray-500'}`}>
                {lang === 'my' ? task.descriptionMy : task.descriptionEn}
              </p>
            </div>

            <div className="flex items-center justify-between">
              <button 
                onClick={() => { 
                  setActiveModalType(task.id === '1' ? 'meditation' : task.id === '2' ? 'intention' : task.id === '3' ? 'gratitude' : 'eating');
                  setShowPrepModal(true); 
                  setPrepStep(0); 
                }}
                className={`px-6 py-3 rounded-2xl font-bold text-[11px] border active-scale transition-all ${
                  task.isCompleted ? 'opacity-0 pointer-events-none' : 'bg-amber-50/50 text-[#D4AF37] border-amber-100'
                }`}
              >
                {t.prepBtn}
              </button>

              <button 
                onClick={() => toggleTask(task.id)}
                className={`px-8 py-3 rounded-2xl font-bold text-[11px] shadow-sm transition-all active-scale ${
                  task.isCompleted ? 'bg-gray-50 text-gray-300' : 'bg-white border border-gray-100 text-gray-400'
                }`}
              >
                {task.isCompleted ? t.undo : t.completeTask}
              </button>
            </div>
          </div>
        ))}
      </section>

      {/* Preparation Modal */}
      {showPrepModal && (
        <div 
          className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-black/30 backdrop-blur-sm animate-fade-in" 
          onClick={() => setShowPrepModal(false)}
          role="dialog"
          aria-modal="true"
        >
          <div className="bg-white rounded-t-[3rem] sm:rounded-[3rem] w-full max-w-lg overflow-hidden shadow-2xl flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
            <div className="bg-[#D4AF37] p-10 text-white relative">
              <button 
                onClick={() => setShowPrepModal(false)} 
                className="absolute top-6 right-6 p-2 bg-white/10 rounded-full hover:bg-white/20"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
              <h4 className="text-[10px] font-bold uppercase tracking-[0.2em] mb-2 opacity-80">Instruction / လမ်းညွှန်</h4>
              <div className="flex items-center gap-4">
                <span className="text-4xl font-serif italic">0{prepStep + 1}</span>
                <span className="text-xs bg-white/20 px-3 py-1 rounded-full font-bold uppercase tracking-wider">{lang === 'my' ? currentQuotes[prepStep].categoryMy : currentQuotes[prepStep].categoryEn}</span>
              </div>
            </div>

            <div className="p-10 md:p-14 overflow-y-auto">
              <blockquote className="border-l-4 border-[#D4AF37] pl-8 py-2 mb-8">
                 <p className="text-2xl text-gray-800 font-serif leading-relaxed italic">
                  {lang === 'my' ? currentQuotes[prepStep].textMy : currentQuotes[prepStep].textEn}
                 </p>
              </blockquote>
            </div>

            <div className="p-8 border-t border-gray-50 flex items-center justify-between bg-gray-50/50">
              <div className="flex gap-2">
                {currentQuotes.slice(0, 5).map((_, i) => (
                  <div key={i} className={`h-1 rounded-full transition-all ${i === prepStep ? 'w-6 bg-[#D4AF37]' : 'w-2 bg-gray-200'}`}></div>
                ))}
              </div>
              <div className="flex gap-3">
                {prepStep > 0 && (
                  <button onClick={() => setPrepStep(s => s - 1)} className="px-6 py-3 border border-gray-200 rounded-2xl text-[10px] font-bold text-gray-400 uppercase active-scale">
                    {t.back}
                  </button>
                )}
                {prepStep < currentQuotes.length - 1 ? (
                  <button onClick={() => setPrepStep(s => s + 1)} className="px-8 py-3 bg-[#006D77] text-white rounded-2xl text-[10px] font-bold shadow-lg uppercase active-scale">
                    {t.next}
                  </button>
                ) : (
                  <button onClick={() => setShowPrepModal(false)} className="px-8 py-3 bg-[#D4AF37] text-white rounded-2xl text-[10px] font-bold shadow-lg uppercase active-scale">
                    {t.close}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Status Messages */}
      {successMessage && (
        <div role="status" className="fixed bottom-12 left-1/2 -translate-x-1/2 bg-[#006D77] text-white px-8 py-4 rounded-3xl shadow-2xl z-[200] animate-fade-in font-bold text-xs tracking-wide">
          {successMessage}
        </div>
      )}

      <footer className="text-center pb-12 opacity-30">
        <p className="text-[10px] tracking-[0.5em] font-bold text-gray-400 uppercase">
          MINDFUL PROJECT / 2026
        </p>
      </footer>
    </div>
  );
};

export default App;
